function VisualNovelStage({
  beats,
  beatIndex,
  currentBeat,
  spriteBeat,
  stepCount,
  isInputStep,
  techDemoEnabled,
  background,
  isAdmin,
  onPrevious,
  onNext,
  onJumpToEnd,
  onGenerateBackground,
  canGenerateBackground,
  isGeneratingBackground,
  backgroundError,
  emptyText,
  mainHeroName,
  resolveSpeakerEntry,
}: {
  beats: StoryNovelBeat[]
  beatIndex: number
  currentBeat: StoryNovelBeat | null
  spriteBeat: StoryNovelBeat | null
  stepCount: number
  isInputStep: boolean
  techDemoEnabled: boolean
  background: StorySceneBackground | null
  isAdmin: boolean
  onPrevious: () => void
  onNext: () => void
  onJumpToEnd: () => void
  onGenerateBackground: () => void | Promise<void>
  canGenerateBackground: boolean
  isGeneratingBackground: boolean
  backgroundError: string
  emptyText: string
  mainHeroName: string
  resolveSpeakerEntry: (speakerName: string) => SpeakerAvatarEntry | null
}) {
  const rawBackgroundUrl = background?.image_url ?? null
  const backgroundUrl = resolveApiResourceUrl(rawBackgroundUrl)
  const speakerName = currentBeat?.speaker_name?.trim() || ''
  const normalizedSpeakerAlias = speakerName
    .toLowerCase()
    .replace(/ё/g, 'е')
    .replace(/[_-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
  const isMainHeroSpeakerAlias = ['главный герой', 'гг', 'main hero', 'mainhero', 'mc'].includes(normalizedSpeakerAlias)
  const speakerLabel = (isMainHeroSpeakerAlias ? mainHeroName : speakerName) || 'Рассказчик'
  const emotionLabel =
    currentBeat?.emotion && STORY_CHARACTER_EMOTION_LABELS[currentBeat.emotion]
      ? STORY_CHARACTER_EMOTION_LABELS[currentBeat.emotion]
      : null
  const beatCount = techDemoEnabled ? stepCount : beats.length
  const isFirstBeat = beatIndex <= 0
  const isLastBeat = beatIndex >= beatCount - 1
  const isPlayerMoveBeat = Boolean(currentBeat?.is_player_move)
  const isDialogueBeat = !isPlayerMoveBeat && currentBeat?.kind === 'dialogue'
  const isThoughtBeat = !isPlayerMoveBeat && currentBeat?.kind === 'thought'
  const isCharacterBeat = isDialogueBeat || isThoughtBeat
  const speakerEntry = isCharacterBeat ? resolveSpeakerEntry(speakerLabel) : null
  const beatAccentColor = resolveSpeakerBubbleColor(speakerEntry, isThoughtBeat)
  const speakerTitleColor = isPlayerMoveBeat
    ? 'var(--morius-accent)'
    : isCharacterBeat
      ? resolveSpeakerNameColor(speakerEntry, 'var(--morius-title-text)')
      : 'var(--morius-title-text)'
  const beatTextColor = isCharacterBeat
    ? resolveSpeakerSpeechColor(speakerEntry, 'var(--morius-text-primary)')
    : 'var(--morius-text-primary)'
  const sourceSpriteBeat = spriteBeat ?? currentBeat
  const activeSpeakerKey = isNovelNonCharacterName(currentBeat?.speaker_name)
    ? ''
    : normalizeNovelCharacterName(currentBeat?.speaker_name)
  const sceneCharacters = useMemo<StoryNovelSceneCharacter[]>(() => {
    const fallbackSpriteGender = sourceSpriteBeat?.speaker_name
      ? inferNovelIncognitoSpriteGender(sourceSpriteBeat.speaker_name, sourceSpriteBeat.sprite_gender)
      : null
    const fallbackSpriteUrl = sourceSpriteBeat?.sprite_url ?? (
      fallbackSpriteGender
        ? STORY_NOVEL_INCOGNITO_SPRITE_URL_BY_GENDER[fallbackSpriteGender]
        : null
    )
    const fallbackSceneCharacter: StoryNovelSceneCharacter[] = (
      sourceSpriteBeat?.speaker_name
      && !isNovelNonCharacterName(sourceSpriteBeat.speaker_name)
      && fallbackSpriteUrl
    )
      ? [{
          character_id: sourceSpriteBeat.speaker_character_id,
          name: sourceSpriteBeat.speaker_name,
          emotion: sourceSpriteBeat.emotion ?? ('neutral' as StoryCharacterEmotionId),
          sprite_url: fallbackSpriteUrl,
          incognito: sourceSpriteBeat.sprite_url ? sourceSpriteBeat.sprite_incognito : true,
          gender: fallbackSpriteGender,
        }]
      : []
    if (techDemoEnabled) {
      // Keep up to three active characters across narration/player pages. Dialogue moves the
      // speaker to the center; narration centers its last-mentioned character and never creates
      // a synthetic "Рассказчик" sprite.
      const spriteBeatIndex = isInputStep ? beats.length - 1 : beatIndex
      const persistentCast = resolveNovelStageCast(beats, spriteBeatIndex, 3)
      return persistentCast.length > 0 ? persistentCast : fallbackSceneCharacter.slice(0, 3)
    }
    // Non-admin shell is unchanged: only the character who is actually speaking is shown.
    return (
      activeSpeakerKey
        ? fallbackSceneCharacter.filter(
            (character) => character.name.trim().toLocaleLowerCase('ru-RU') === activeSpeakerKey,
          )
        : fallbackSceneCharacter
    ).slice(0, 1)
  }, [activeSpeakerKey, beatIndex, beats, isInputStep, sourceSpriteBeat, techDemoEnabled])
  const animatedSceneCharacters = useAnimatedNovelStageCast(
    sceneCharacters,
    `${currentBeat?.id ?? 'empty'}:${beatIndex}:${isInputStep ? 'input' : 'beat'}`,
  )
  // Shared step-nav button styling. Kept identical to the composer's nav so the controls do not
  // shift position when the player crosses from reading beats into their own turn.
  const stepNavButtonSx = {
    width: { xs: 28, md: 30 },
    height: { xs: 28, md: 30 },
    minWidth: { xs: 28, md: 30 },
    minHeight: { xs: 28, md: 30 },
    p: 0,
    borderRadius: '10px',
    fontSize: '1.2rem',
    lineHeight: 1,
    fontWeight: 700,
    color: 'var(--morius-title-text)',
    border: '1px solid rgba(255,255,255,0.14)',
    backgroundColor: 'rgba(255,255,255,0.04)',
    transition: 'background-color 160ms ease, opacity 160ms ease, transform 160ms ease',
    '&:hover': { backgroundColor: 'rgba(255,255,255,0.1)', transform: 'translateY(-1px)' },
    '&:active': { transform: 'translateY(1px)' },
    '&:disabled': {
      opacity: 0.32,
      color: 'var(--morius-text-secondary)',
      backgroundColor: 'rgba(255,255,255,0.03)',
    },
  }

  return (
    <Box
      sx={{
        // Tech-demo VN is anchored straight to the viewport (like the composer) so it always
        // fills the screen from just under the header to the bottom edge — independent of the
        // surrounding flex/scroll chain. Sprites float above the dialogue box, which sits flush
        // at the bottom next to the "Ваш ход" composer.
        position: techDemoEnabled ? 'fixed' : 'relative',
        ...(techDemoEnabled
          ? { top: 'var(--morius-header-menu-top)', left: 0, right: 0, bottom: 0, zIndex: 1 }
          : {}),
        width: techDemoEnabled ? 'auto' : '100%',
        minHeight: techDemoEnabled
          ? undefined
          : { xs: 'calc(100vh - 238px)', md: 'min(680px, calc(100vh - 214px))' },
        height: techDemoEnabled
          ? undefined
          : { xs: 'calc(100vh - 238px)', md: 'min(680px, calc(100vh - 214px))' },
        overflow: 'hidden',
        borderRadius: techDemoEnabled ? 0 : '8px',
        border: techDemoEnabled
          ? 'none'
          : 'var(--morius-border-width) solid color-mix(in srgb, var(--morius-card-border) 72%, transparent)',
        background:
          'linear-gradient(180deg, color-mix(in srgb, var(--morius-card-bg) 86%, #050506 14%) 0%, color-mix(in srgb, var(--morius-app-bg) 94%, #000 6%) 100%)',
      }}
    >
      {backgroundUrl ? (
        <ProgressiveImage
          src={backgroundUrl}
          alt=""
          loading="eager"
          fetchPriority="high"
          objectFit="cover"
          loaderSize={30}
          containerSx={{
            position: 'absolute',
            inset: 0,
            width: '100%',
            height: '100%',
          }}
          imgSx={{
            position: 'absolute',
            inset: 0,
            width: '100%',
            height: '100%',
            filter: techDemoEnabled ? 'saturate(0.96) contrast(1.03)' : 'saturate(0.94) contrast(1.02)',
          }}
        />
      ) : (
        <Box
          sx={{
            position: 'absolute',
            inset: 0,
            background:
              'linear-gradient(135deg, color-mix(in srgb, var(--morius-elevated-bg) 94%, #000 6%) 0%, color-mix(in srgb, var(--morius-card-bg) 78%, #000 22%) 50%, color-mix(in srgb, var(--morius-accent) 22%, #07080b 78%) 100%)',
          }}
        />
      )}
      <Box
        sx={{
          position: 'absolute',
          inset: 0,
          background:
            techDemoEnabled
              ? 'linear-gradient(180deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0.02) 42%, rgba(0,0,0,0.76) 100%)'
              : 'linear-gradient(180deg, rgba(0,0,0,0.12) 0%, rgba(0,0,0,0.08) 46%, rgba(0,0,0,0.66) 100%)',
        }}
      />

      {animatedSceneCharacters.map((entry) => {
        const { character, castCount, phase, slotIndex } = entry
        const spriteUrl = resolveApiResourceUrl(character.sprite_url)
        const normalizedName = normalizeNovelCharacterName(character.name)
        const isActiveSpeaker = !activeSpeakerKey
          || (currentBeat?.speaker_character_id != null
            && character.character_id === currentBeat.speaker_character_id)
          || normalizedName === activeSpeakerKey
        // Slot zero is deliberately the focus slot. The cast resolver puts the current speaker
        // there on dialogue pages and the last-mentioned active character on narration pages.
        const desktopPositions = castCount === 1
          ? ['50%']
          : castCount === 2
            ? ['50%', '24%']
            : ['50%', '24%', '76%']
        const mobilePositions = castCount === 1
          ? ['50%']
          : castCount === 2
            ? ['50%', '20%']
            : ['50%', '20%', '80%']
        const isCenterCharacter = slotIndex === 0
        const settledOpacity = techDemoEnabled && activeSpeakerKey && !isActiveSpeaker ? 0.78 : 1
        const phaseOpacity = phase === 'entering' || phase === 'exiting'
          ? 0
          : phase === 'switching'
            ? settledOpacity * 0.88
            : settledOpacity
        const baseScale = techDemoEnabled && !isCenterCharacter ? 0.94 : 1
        const phaseScale = phase === 'entering'
          ? baseScale * 0.9
          : phase === 'switching'
            ? baseScale * 0.97
            : phase === 'exiting'
              ? baseScale * 0.92
              : baseScale
        const phaseTranslateY = phase === 'entering' ? '4%' : phase === 'exiting' ? '5%' : '0%'
        return (
          <Box
            key={entry.key}
            sx={{
              position: 'absolute',
              left: {
                xs: mobilePositions[slotIndex] ?? '50%',
                md: desktopPositions[slotIndex] ?? '50%',
              },
              bottom: techDemoEnabled ? { xs: 150, sm: 170, md: 188 } : { xs: 118, md: 126 },
              width: techDemoEnabled
                ? {
                    xs: castCount === 1 ? '92vw' : castCount === 2 ? '68vw' : '56vw',
                    sm: castCount === 1 ? '66vw' : castCount === 2 ? '49vw' : '42vw',
                    md: castCount === 1 ? 'min(46vw, 620px)' : castCount === 2 ? 'min(38vw, 530px)' : 'min(32vw, 470px)',
                  }
                : { xs: '72%', sm: '58%', md: '46%' },
              height: techDemoEnabled ? { xs: '64%', sm: '70%', md: '76%' } : { xs: '58%', md: '66%' },
              transform: `translateX(-50%) translateY(${phaseTranslateY}) scale(${phaseScale})`,
              transformOrigin: 'center bottom',
              display: 'flex',
              alignItems: 'flex-end',
              justifyContent: 'center',
              opacity: phaseOpacity,
              filter: phase === 'exiting'
                ? 'saturate(0.62) brightness(0.68) blur(2px)'
                : techDemoEnabled && activeSpeakerKey && !isActiveSpeaker
                  ? 'saturate(0.78) brightness(0.82)'
                  : 'none',
              transition: [
                `left ${NOVEL_STAGE_SPRITE_TRANSITION_MS}ms cubic-bezier(0.22, 1, 0.36, 1)`,
                `width ${NOVEL_STAGE_SPRITE_TRANSITION_MS}ms cubic-bezier(0.22, 1, 0.36, 1)`,
                `opacity ${NOVEL_STAGE_SPRITE_TRANSITION_MS - 80}ms ease`,
                `filter ${NOVEL_STAGE_SPRITE_TRANSITION_MS - 80}ms ease`,
                `transform ${NOVEL_STAGE_SPRITE_TRANSITION_MS}ms cubic-bezier(0.22, 1, 0.36, 1)`,
              ].join(', '),
              willChange: 'left, width, opacity, filter, transform',
              pointerEvents: 'none',
              zIndex: phase === 'exiting' ? 0 : isCenterCharacter ? 4 : isActiveSpeaker ? 3 : 1,
              '@media (prefers-reduced-motion: reduce)': {
                transitionDuration: '1ms',
              },
            }}
          >
            {spriteUrl ? (
              <NovelStageSpriteImage
                src={spriteUrl}
                name={character.name}
                techDemoEnabled={techDemoEnabled}
              />
            ) : null}
          </Box>
        )
      })}

      {isAdmin && (!techDemoEnabled || !isInputStep) ? (
        <Stack
          direction="row"
          spacing={0.65}
          sx={{
            position: 'absolute',
            top: 12,
            right: 12,
            zIndex: 3,
          }}
        >
          <Tooltip arrow disableInteractive placement="bottom" title="Сгенерировать фон">
            <span>
              <IconButton
                aria-label="Сгенерировать фон"
                onClick={() => {
                  void Promise.resolve(onGenerateBackground()).catch(() => undefined)
                }}
                disabled={!canGenerateBackground}
                sx={{
                  width: 42,
                  height: 42,
                  borderRadius: '14px',
                  color: 'var(--morius-title-text)',
                  backgroundColor: 'rgba(0,0,0,0.32)',
                  border: 'var(--morius-border-width) solid rgba(255,255,255,0.18)',
                  backdropFilter: 'blur(10px)',
                }}
              >
                {isGeneratingBackground
                  ? <CircularProgress size={18} sx={{ color: 'var(--morius-accent)' }} />
                  : <NovelSceneBackdropIcon />}
              </IconButton>
            </span>
          </Tooltip>
        </Stack>
      ) : null}

      {isGeneratingBackground ? (
        <Stack
          direction="row"
          alignItems="center"
          spacing={0.85}
          sx={{
            position: 'absolute',
            top: 14,
            left: '50%',
            transform: 'translateX(-50%)',
            zIndex: 5,
            px: 1.35,
            py: 0.7,
            borderRadius: '999px',
            backgroundColor: 'rgba(6, 8, 14, 0.72)',
            border: '1px solid rgba(255,255,255,0.16)',
            backdropFilter: 'blur(12px)',
            maxWidth: '86%',
          }}
        >
          <CircularProgress size={15} thickness={5} sx={{ color: 'var(--morius-accent)' }} />
          <Typography sx={{ color: 'rgba(255,255,255,0.94)', fontSize: '0.78rem', fontWeight: 700, whiteSpace: 'nowrap' }}>
            Генерирую фон сцены…
          </Typography>
        </Stack>
      ) : null}

      {backgroundError && !isGeneratingBackground ? (
        <Box
          sx={{
            position: 'absolute',
            top: 58,
            left: '50%',
            transform: 'translateX(-50%)',
            zIndex: 4,
            px: 1.2,
            py: 0.65,
            borderRadius: '999px',
            backgroundColor: 'rgba(64, 20, 20, 0.7)',
            border: '1px solid rgba(255,255,255,0.14)',
            backdropFilter: 'blur(10px)',
            maxWidth: '80%',
          }}
        >
          <Typography sx={{ color: 'rgba(255,255,255,0.92)', fontSize: '0.78rem', fontWeight: 700 }}>
            {backgroundError}
          </Typography>
        </Box>
      ) : null}

      {!isInputStep ? <Box
        sx={{
          position: 'absolute',
          left: techDemoEnabled ? { xs: 10, sm: 18, md: 'max(24px, calc((100% - 1180px) / 2))' } : { xs: 10, md: 18 },
          right: techDemoEnabled ? { xs: 10, sm: 18, md: 'max(24px, calc((100% - 1180px) / 2))' } : { xs: 10, md: 18 },
          bottom: techDemoEnabled ? { xs: 10, sm: 16, md: 22 } : { xs: 10, md: 14 },
          zIndex: 4,
          // Match the composer footprint so the step nav sits in the exact same spot whether
          // the player is reading a beat or on their own turn.
          minHeight: techDemoEnabled ? { xs: 198, md: 226 } : undefined,
          borderRadius: techDemoEnabled ? { xs: '18px', md: '22px' } : '8px',
          border: techDemoEnabled ? '1px solid rgba(255,255,255,0.12)' : 'var(--morius-border-width) solid rgba(255,255,255,0.16)',
          background: techDemoEnabled ? 'rgba(9, 10, 15, 0.76)' : 'color-mix(in srgb, var(--morius-card-bg) 88%, #000 12%)',
          boxShadow: techDemoEnabled ? '0 22px 70px rgba(0,0,0,0.36)' : 'none',
          backdropFilter: techDemoEnabled ? 'blur(22px) saturate(116%)' : 'blur(18px)',
          p: techDemoEnabled ? { xs: 1.4, sm: 1.65, md: 2 } : { xs: 1.15, md: 1.35 },
        }}
      >
        <Stack spacing={0.85}>
          <Stack direction="row" alignItems="center" justifyContent="space-between" spacing={1}>
            <Stack direction="row" alignItems="center" spacing={0.7} sx={{ minWidth: 0 }}>
              <Typography
                sx={{
                  minWidth: 0,
                  color: speakerTitleColor,
                  fontSize: { xs: '0.92rem', md: '1rem' },
                  lineHeight: 1.15,
                  fontWeight: 900,
                  whiteSpace: 'nowrap',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                }}
              >
                {isPlayerMoveBeat ? 'Ваш ход' : speakerLabel}
              </Typography>
              {isCharacterBeat ? (
                <Typography
                  sx={{
                    color: beatAccentColor,
                    fontSize: '0.65rem',
                    lineHeight: 1,
                    fontWeight: 900,
                    letterSpacing: '0.08em',
                    whiteSpace: 'nowrap',
                    flexShrink: 0,
                  }}
                >
                  {isThoughtBeat ? '· В ГОЛОВЕ' : '· РЕПЛИКА'}
                </Typography>
              ) : null}
              {emotionLabel && !isPlayerMoveBeat ? (
                <Typography
                  sx={{
                    color: 'var(--morius-text-secondary)',
                    fontSize: '0.78rem',
                    lineHeight: 1,
                    fontWeight: 700,
                    whiteSpace: 'nowrap',
                  }}
                >
                  {emotionLabel}
                </Typography>
              ) : null}
            </Stack>
            {techDemoEnabled ? (
              <Stack direction="row" alignItems="center" spacing={0.45} sx={{ flexShrink: 0 }}>
                <IconButton aria-label="Назад" onClick={onPrevious} disabled={isFirstBeat} sx={stepNavButtonSx}>
                  {'‹'}
                </IconButton>
                <Typography
                  sx={{
                    minWidth: 38,
                    textAlign: 'center',
                    color: 'var(--morius-text-secondary)',
                    fontSize: '0.76rem',
                    fontWeight: 800,
                    fontVariantNumeric: 'tabular-nums',
                  }}
                >
                  {beatCount > 0 ? `${beatIndex + 1}/${beatCount}` : '1/1'}
                </Typography>
                <IconButton aria-label="Вперед" onClick={onNext} disabled={isLastBeat} sx={stepNavButtonSx}>
                  {'›'}
                </IconButton>
              </Stack>
            ) : (
              <Typography sx={{ color: 'var(--morius-text-secondary)', fontSize: '0.78rem', fontWeight: 800, flexShrink: 0 }}>
                {beatCount > 0 ? `${beatIndex + 1}/${beatCount}` : '0/0'}
              </Typography>
            )}
          </Stack>
          <Typography
            sx={{
              color: beatTextColor,
              fontSize: { xs: '1rem', md: '1.1rem' },
              lineHeight: 1.48,
              whiteSpace: 'pre-wrap',
              fontStyle: isPlayerMoveBeat || isThoughtBeat ? 'italic' : 'normal',
              minHeight: techDemoEnabled ? { xs: 80, md: 98 } : { xs: 72, md: 84 },
              maxHeight: techDemoEnabled ? { xs: 148, md: 180 } : { xs: 132, md: 150 },
              overflowY: 'auto',
              ...(isCharacterBeat
                ? {
                    borderLeft: `3px solid ${beatAccentColor}`,
                    backgroundColor: `color-mix(in srgb, ${beatAccentColor} 16%, transparent)`,
                    borderRadius: '0 10px 10px 0',
                    px: { xs: 1.25, md: 1.5 },
                    py: { xs: 0.9, md: 1 },
                  }
                : {}),
            }}
          >
            {currentBeat ? replaceMainHeroInlineTags(currentBeat.text, mainHeroName) : emptyText}
          </Typography>
          {!techDemoEnabled ? (
            <Stack direction="row" alignItems="center" justifyContent="space-between" spacing={1}>
              <Stack direction="row" spacing={0.65}>
                <Tooltip arrow disableInteractive placement="top" title="Назад">
                  <span>
                    <IconButton
                      aria-label="Назад"
                      onClick={onPrevious}
                      disabled={isFirstBeat}
                      sx={{
                        width: 36,
                        height: 36,
                        color: 'var(--morius-title-text)',
                        border: 'var(--morius-border-width) solid color-mix(in srgb, var(--morius-card-border) 82%, transparent)',
                      }}
                    >
                      {'‹'}
                    </IconButton>
                  </span>
                </Tooltip>
                <Tooltip arrow disableInteractive placement="top" title="Вперед">
                  <span>
                    <IconButton
                      aria-label="Вперед"
                      onClick={onNext}
                      disabled={isLastBeat}
                      sx={{
                        width: 36,
                        height: 36,
                        color: 'var(--morius-title-text)',
                        border: 'var(--morius-border-width) solid color-mix(in srgb, var(--morius-card-border) 82%, transparent)',
                      }}
                    >
                      {'›'}
                    </IconButton>
                  </span>
                </Tooltip>
              </Stack>
              {!isLastBeat ? (
                <Button
                  onClick={onJumpToEnd}
                  sx={{
                    minHeight: 34,
                    borderRadius: '8px',
                    px: 1.1,
                    textTransform: 'none',
                    color: 'var(--morius-title-text)',
                    border: 'var(--morius-border-width) solid color-mix(in srgb, var(--morius-card-border) 78%, transparent)',
                  }}
                >
                  Конец
                </Button>
              ) : null}
            </Stack>
          ) : null}
        </Stack>
      </Box> : null}
    </Box>
  )
}

function ViewToggleButton({
  cardsViewMode,
  setCardsViewMode,
}: {
  cardsViewMode: 'full' | 'compact'
  setCardsViewMode: (mode: 'full' | 'compact') => void
}) {
  return (
    <Box
      component="button"
      type="button"
      onClick={() => {
        const next = cardsViewMode === 'full' ? 'compact' : 'full'
        setCardsViewMode(next)
        try { localStorage.setItem('morius-cards-view-mode', next) } catch { /* ignore */ }
      }}
      title={cardsViewMode === 'full' ? 'Компактный вид' : 'Полный вид'}
      aria-label={cardsViewMode === 'full' ? 'Переключить в компактный вид' : 'Переключить в полный вид'}
      sx={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: 0.55,
        px: 1.1,
        py: 0.5,
        border: 'var(--morius-border-width) solid color-mix(in srgb, var(--morius-card-border) 80%, transparent)',
        borderRadius: '8px',
        backgroundColor: 'transparent',
        color: 'var(--morius-text-secondary)',
        fontSize: '0.76rem',
        fontWeight: 600,
        fontFamily: 'inherit',
        cursor: 'pointer',
        flexShrink: 0,
        transition: 'color 140ms ease, border-color 140ms ease, background-color 140ms ease',
        '&:hover': {
          color: 'var(--morius-text-primary)',
          borderColor: 'var(--morius-card-border)',
          backgroundColor: 'rgba(255,255,255,0.05)',
        },
      }}
    >
      {cardsViewMode === 'full' ? (
        <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
          <rect x="0" y="1" width="5" height="12" rx="1.5" fill="currentColor" opacity="0.7"/>
          <line x1="7" y1="3" x2="14" y2="3" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
          <line x1="7" y1="7" x2="14" y2="7" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
          <line x1="7" y1="11" x2="14" y2="11" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
        </svg>
      ) : (
        <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
          <rect x="0" y="0" width="6" height="14" rx="1.5" fill="currentColor" opacity="0.7"/>
          <rect x="8" y="0" width="6" height="14" rx="1.5" fill="currentColor" opacity="0.5"/>
        </svg>
      )}
      {cardsViewMode === 'full' ? 'Компакт' : 'Полный'}
    </Box>
  )
}

