const STORY_AMBIENT_HEX_COLOR_PATTERN = /^#?(?:[0-9a-f]{3}|[0-9a-f]{6})$/i
const STORY_AMBIENT_DEFAULT_PROFILE: StoryAmbientProfile = {
  scene: 'unknown',
  lighting: 'dim',
  primary_color: '#101826',
  secondary_color: '#1a2436',
  highlight_color: '#324865',
  glow_strength: 0.2,
  background_mix: 0.18,
  vignette_strength: 0.34,
}

const STORY_AMBIENT_YAMI_PROFILE: StoryAmbientProfile = {
  scene: 'unknown',
  lighting: 'dim',
  primary_color: '#2A2323',
  secondary_color: '#222222',
  highlight_color: '#FF6666',
  glow_strength: 0.2,
  background_mix: 0.18,
  vignette_strength: 0.34,
}

function clampAmbientValue(
  value: number | null | undefined,
  minimum: number,
  maximum: number,
  fallback: number,
): number {
  const numericValue = typeof value === 'number' ? value : Number.NaN
  if (!Number.isFinite(numericValue)) {
    return fallback
  }
  return Math.max(minimum, Math.min(numericValue, maximum))
}

function normalizeAmbientHexColor(value: string | null | undefined, fallback: string): string {
  const normalizedValue = (value ?? '').trim().toLowerCase()
  if (!STORY_AMBIENT_HEX_COLOR_PATTERN.test(normalizedValue)) {
    return fallback
  }
  const colorValue = normalizedValue.startsWith('#') ? normalizedValue.slice(1) : normalizedValue
  if (colorValue.length === 3) {
    return `#${colorValue
      .split('')
      .map((item) => `${item}${item}`)
      .join('')}`
  }
  return `#${colorValue}`
}

function hexToRgba(hexColor: string, alpha: number): string {
  const normalizedColor = normalizeAmbientHexColor(hexColor, STORY_AMBIENT_DEFAULT_PROFILE.primary_color)
  const colorValue = normalizedColor.slice(1)
  const red = Number.parseInt(colorValue.slice(0, 2), 16)
  const green = Number.parseInt(colorValue.slice(2, 4), 16)
  const blue = Number.parseInt(colorValue.slice(4, 6), 16)
  return `rgba(${red}, ${green}, ${blue}, ${clampAmbientValue(alpha, 0, 1, 0)})`
}

function normalizeStoryAmbientProfile(
  value: Partial<StoryAmbientProfile> | null | undefined,
): StoryAmbientProfile {
  if (!value) {
    return STORY_AMBIENT_DEFAULT_PROFILE
  }
  const defaultProfile = STORY_AMBIENT_DEFAULT_PROFILE
  const normalizeLabel = (rawValue: string | null | undefined, fallback: string) => {
    const normalizedValue = (rawValue ?? '').replace(/\r\n/g, ' ').trim().replace(/\s+/g, ' ')
    if (!normalizedValue) {
      return fallback
    }
    return normalizedValue.slice(0, 80)
  }
  return {
    scene: normalizeLabel(value.scene, defaultProfile.scene),
    lighting: normalizeLabel(value.lighting, defaultProfile.lighting),
    primary_color: normalizeAmbientHexColor(value.primary_color, defaultProfile.primary_color),
    secondary_color: normalizeAmbientHexColor(value.secondary_color, defaultProfile.secondary_color),
    highlight_color: normalizeAmbientHexColor(value.highlight_color, defaultProfile.highlight_color),
    glow_strength: clampAmbientValue(value.glow_strength, 0, 1, defaultProfile.glow_strength),
    background_mix: clampAmbientValue(value.background_mix, 0, 1, defaultProfile.background_mix),
    vignette_strength: clampAmbientValue(value.vignette_strength, 0, 1, defaultProfile.vignette_strength),
  }
}

function toStoryText(value: unknown): string {
  return typeof value === 'string' ? value : ''
}

function toStoryStringList(value: unknown): string[] {
  if (!Array.isArray(value)) {
    return []
  }
  return value
    .map((item) => toStoryText(item).trim())
    .filter((item) => item.length > 0)
}

function normalizeStoryMessageItem(message: StoryMessage): StoryMessage {
  return {
    ...message,
    content: toStoryText(message.content),
  }
}

const NOVEL_NON_CHARACTER_NAMES = new Set([
  'narrator',
  'рассказчик',
  'автор',
  'система',
  'system',
  'scene',
  'сцена',
  'повествователь',
  'описание',
])

function normalizeNovelCharacterName(value: string | null | undefined): string {
  return (value ?? '')
    .trim()
    .toLocaleLowerCase('ru-RU')
    .replace(/ё/g, 'е')
    .replace(/[_-]+/g, ' ')
    .replace(/\s+/g, ' ')
}

function isNovelNonCharacterName(value: string | null | undefined): boolean {
  return NOVEL_NON_CHARACTER_NAMES.has(normalizeNovelCharacterName(value))
}

function inferNovelIncognitoSpriteGender(
  name: string | null | undefined,
  explicitGender?: string | null,
): 'male' | 'female' {
  const explicit = (explicitGender ?? '').trim().toLocaleLowerCase('en-US')
  if (explicit === 'female' || explicit === 'male') {
    return explicit
  }

  const normalizedName = normalizeNovelCharacterName(name)
  const tokens = normalizedName.split(/[^a-zа-я]+/iu).filter(Boolean)
  const femaleStems = [
    'женщин', 'девушк', 'девочк', 'героин', 'королев', 'принцесс', 'герцогин',
    'графин', 'баронесс', 'учительниц', 'преподавательниц', 'директрис', 'наставниц',
    'хозяйк', 'служанк', 'горничн', 'монахин', 'жриц', 'ведьм', 'волшебниц', 'колдунь',
  ]
  const femaleWords = new Set([
    'мать', 'мама', 'дочь', 'сестра', 'жена', 'леди', 'female', 'woman', 'girl',
    'mother', 'daughter', 'sister', 'queen', 'princess', 'duchess', 'lady',
  ])
  if (tokens.some((token) => femaleWords.has(token) || femaleStems.some((stem) => token.startsWith(stem)))) {
    return 'female'
  }

  const maleWords = new Set([
    'мужчина', 'парень', 'юноша', 'мальчик', 'отец', 'папа', 'сын', 'брат', 'муж',
    'король', 'принц', 'герцог', 'граф', 'барон', 'лорд', 'учитель', 'преподаватель',
    'директор', 'наставник', 'хозяин', 'слуга', 'монах', 'жрец', 'колдун', 'волшебник',
    'стражник', 'охранник', 'male', 'man', 'boy', 'father', 'son', 'brother', 'king',
    'prince', 'duke', 'lord',
  ])
  if (tokens.some((token) => maleWords.has(token))) {
    return 'male'
  }

  const lastToken = tokens.at(-1) ?? ''
  const masculineAEndingNames = new Set(['илья', 'никита', 'лука', 'кузьма', 'фома', 'савва', 'данила', 'миша', 'саша'])
  if (lastToken && !masculineAEndingNames.has(lastToken) && /[ая]$/u.test(lastToken)) {
    return 'female'
  }
  // Old beats can contain no gender at all. A real fallback is preferable to silently dropping
  // the cast member; new turns still receive the narrator's explicit male/female metadata.
  return 'male'
}

function normalizeStoryVNBeatItem(beat: StoryNovelBeat): StoryNovelBeat {
  const rawEmotion = typeof beat.emotion === 'string' ? beat.emotion : null
  const speakerName = typeof beat.speaker_name === 'string' && beat.speaker_name.trim()
    ? beat.speaker_name.trim()
    : null
  const spriteGender = speakerName
    ? inferNovelIncognitoSpriteGender(speakerName, beat.sprite_gender)
    : null
  const rawSpriteUrl = typeof beat.sprite_url === 'string' && beat.sprite_url.trim()
    ? beat.sprite_url.trim()
    : null
  const spriteUrl = rawSpriteUrl ?? (
    speakerName && (beat.kind === 'dialogue' || beat.kind === 'thought') && spriteGender
      ? STORY_NOVEL_INCOGNITO_SPRITE_URL_BY_GENDER[spriteGender]
      : null
  )
  return {
    ...beat,
    id: Number.isFinite(beat.id) ? Math.trunc(beat.id) : 0,
    game_id: Number.isFinite(beat.game_id) ? Math.trunc(beat.game_id) : 0,
    message_id: Number.isFinite(beat.message_id) ? Math.trunc(beat.message_id) : 0,
    order_index: Number.isFinite(beat.order_index) ? Math.max(0, Math.trunc(beat.order_index)) : 0,
    kind: beat.kind === 'dialogue' || beat.kind === 'thought' ? beat.kind : 'narration',
    speaker_character_id:
      typeof beat.speaker_character_id === 'number' && Number.isFinite(beat.speaker_character_id)
        ? Math.trunc(beat.speaker_character_id)
        : null,
    speaker_name: speakerName,
    emotion:
      rawEmotion && STORY_CHARACTER_EMOTION_IDS.includes(rawEmotion as StoryCharacterEmotionId)
        ? (rawEmotion as StoryCharacterEmotionId)
        : null,
    text: toStoryText(beat.text),
    sprite_url: spriteUrl,
    sprite_incognito: rawSpriteUrl ? Boolean(beat.sprite_incognito) : Boolean(spriteUrl),
    sprite_gender: spriteGender,
    scene_characters: Array.isArray(beat.scene_characters)
      ? beat.scene_characters
          .filter((character) => Boolean(character) && typeof character === 'object')
          .map((character) => {
            const rawCharacterEmotion = typeof character.emotion === 'string' ? character.emotion : 'neutral'
            const rawCharacterGender = typeof character.gender === 'string' ? character.gender : ''
            const name = typeof character.name === 'string' ? character.name.trim() : ''
            const gender = name ? inferNovelIncognitoSpriteGender(name, rawCharacterGender) : null
            const rawCharacterSpriteUrl =
              typeof character.sprite_url === 'string' && character.sprite_url.trim()
                ? character.sprite_url.trim()
                : null
            return {
              character_id:
                typeof character.character_id === 'number' && Number.isFinite(character.character_id)
                  ? Math.trunc(character.character_id)
                  : null,
              name,
              emotion: STORY_CHARACTER_EMOTION_IDS.includes(rawCharacterEmotion as StoryCharacterEmotionId)
                ? (rawCharacterEmotion as StoryCharacterEmotionId)
                : 'neutral',
              sprite_url: rawCharacterSpriteUrl ?? (
                gender ? STORY_NOVEL_INCOGNITO_SPRITE_URL_BY_GENDER[gender] : null
              ),
              incognito: rawCharacterSpriteUrl ? Boolean(character.incognito) : Boolean(gender),
              gender,
            }
          })
          .filter((character) => character.name.length > 0 && !isNovelNonCharacterName(character.name))
          .slice(0, 3)
      : [],
    created_at: typeof beat.created_at === 'string' ? beat.created_at : new Date(0).toISOString(),
    updated_at: typeof beat.updated_at === 'string' ? beat.updated_at : new Date(0).toISOString(),
  }
}

function normalizeStoryVNBeats(items: StoryNovelBeat[] | null | undefined): StoryNovelBeat[] {
  return Array.isArray(items)
    ? items
        .map((item) => normalizeStoryVNBeatItem(item))
        .filter((item) => item.id > 0 && item.message_id > 0 && item.text.trim().length > 0)
        .sort((left, right) => left.message_id - right.message_id || left.order_index - right.order_index || left.id - right.id)
    : []
}

const VN_SCENE_CAST_FALLBACK_SUFFIX = /\s*\{\{\s*(?:VN_CAST|SCENE_CAST)\s*\|\s*([^}\n]{1,600})\}\}\s*$/i

function parseOpeningFallbackSceneCast(text: string): {
  text: string
  characters: StoryNovelBeat['scene_characters']
} {
  const match = VN_SCENE_CAST_FALLBACK_SUFFIX.exec(text)
  if (!match) {
    return { text, characters: [] }
  }
  const normalizedText = text.slice(0, match.index).trim()
  const rawCast = match[1]?.trim() ?? ''
  if (!rawCast || ['-', 'нет', 'none', 'empty'].includes(rawCast.toLocaleLowerCase('ru-RU'))) {
    return { text: normalizedText, characters: [] }
  }
  const labelToEmotion = new Map<string, StoryCharacterEmotionId>(
    STORY_CHARACTER_EMOTION_IDS.flatMap((emotionId) => [
      [emotionId.toLocaleLowerCase('ru-RU'), emotionId] as const,
      [STORY_CHARACTER_EMOTION_LABELS[emotionId].toLocaleLowerCase('ru-RU'), emotionId] as const,
    ]),
  )
  const seenNames = new Set<string>()
  const characters: StoryNovelBeat['scene_characters'] = []
  for (const item of rawCast.split(';')) {
    const parts = item.split('|').map((part) => part.trim())
    let rawName = parts[0] ?? ''
    let rawEmotion = 'neutral'
    let gender: 'male' | 'female' | null = null
    if (parts.length >= 3) {
      const firstTail = parts.at(-2) ?? ''
      const secondTail = parts.at(-1) ?? ''
      const firstTailGender = firstTail.toLocaleLowerCase('en-US')
      const secondTailGender = secondTail.toLocaleLowerCase('en-US')
      if (firstTailGender === 'male' || firstTailGender === 'female') {
        rawName = parts.slice(0, -2).join('|')
        gender = firstTailGender
        rawEmotion = secondTail
      } else if (secondTailGender === 'male' || secondTailGender === 'female') {
        // Tolerate a provider swapping Gender and Emotion while keeping the legacy format safe.
        rawName = parts.slice(0, -2).join('|')
        gender = secondTailGender
        rawEmotion = firstTail
      } else {
        rawName = parts.slice(0, -1).join('|')
        rawEmotion = secondTail
      }
    } else if (parts.length === 2) {
      rawName = parts[0] ?? ''
      rawEmotion = parts[1] ?? 'neutral'
    }
    const name = rawName.trim()
    const normalizedName = name.toLocaleLowerCase('ru-RU')
    if (!name || isNovelNonCharacterName(name) || seenNames.has(normalizedName)) {
      continue
    }
    seenNames.add(normalizedName)
    gender = inferNovelIncognitoSpriteGender(name, gender)
    characters.push({
      character_id: null,
      name,
      emotion: labelToEmotion.get(rawEmotion.trim().toLocaleLowerCase('ru-RU')) ?? 'neutral',
      sprite_url: STORY_NOVEL_INCOGNITO_SPRITE_URL_BY_GENDER[gender],
      incognito: true,
      gender,
    })
    if (characters.length >= 3) {
      break
    }
  }
  return { text: normalizedText, characters }
}

function buildOpeningSceneFallbackVNBeats(
  blocks: AssistantMessageBlock[],
  game: StoryGameSummary | null,
): StoryNovelBeat[] {
  if (!game || blocks.length === 0) {
    return []
  }
  const timestamp = game.updated_at || game.created_at || new Date(0).toISOString()
  return blocks.map((block, index) => {
    const isCharacterBeat = block.type === 'character'
    const parsedScene = parseOpeningFallbackSceneCast(block.text)
    const speakerSceneCharacter = isCharacterBeat && !isNovelNonCharacterName(block.speakerName)
      ? (() => {
          const gender = inferNovelIncognitoSpriteGender(block.speakerName)
          return {
            character_id: null,
            name: block.speakerName,
            emotion: 'neutral' as StoryCharacterEmotionId,
            sprite_url: STORY_NOVEL_INCOGNITO_SPRITE_URL_BY_GENDER[gender],
            incognito: true,
            gender,
          }
        })()
      : null
    const hasSpeakerInScene = speakerSceneCharacter
      ? parsedScene.characters.some(
          (character) => character.name.toLocaleLowerCase('ru-RU') === speakerSceneCharacter.name.toLocaleLowerCase('ru-RU'),
        )
      : true
    const fallbackSceneCharacters = speakerSceneCharacter && !hasSpeakerInScene
      ? [...parsedScene.characters.slice(0, 2), speakerSceneCharacter]
      : parsedScene.characters
    const activeSpeakerSceneCharacter = speakerSceneCharacter
      ? fallbackSceneCharacters.find(
          (character) => character.name.toLocaleLowerCase('ru-RU') === speakerSceneCharacter.name.toLocaleLowerCase('ru-RU'),
        ) ?? speakerSceneCharacter
      : null
    return {
      // Negative local IDs keep this compatibility fallback out of persisted/merged beat state.
      id: -(index + 1),
      game_id: game.id,
      message_id: -1,
      order_index: index,
      kind: isCharacterBeat ? (block.delivery === 'thought' ? 'thought' : 'dialogue') : 'narration',
      speaker_name: isCharacterBeat ? block.speakerName : null,
      speaker_character_id: null,
      emotion: isCharacterBeat ? 'neutral' : null,
      text: parsedScene.text,
      sprite_url: activeSpeakerSceneCharacter?.sprite_url ?? null,
      sprite_incognito: isCharacterBeat,
      sprite_gender: activeSpeakerSceneCharacter?.gender ?? null,
      scene_characters: fallbackSceneCharacters,
      created_at: timestamp,
      updated_at: timestamp,
    }
  })
}

function normalizeStoryVNCharacterKey(character: StoryNovelSceneCharacter): string {
  if (character.character_id != null && Number.isFinite(character.character_id)) {
    return `id:${character.character_id}`
  }
  const name = character.name.trim().toLocaleLowerCase('ru-RU').replace(/ё/g, 'е')
  return name ? `name:${name}` : ''
}

// True when `character` is the one actually speaking/thinking in `beat` — i.e. the beat's own
// emotion belongs to them. Their scene_characters entry then carries the authoritative sprite.
function beatSpeakerMatchesCharacter(beat: StoryNovelBeat, character: StoryNovelSceneCharacter): boolean {
  if (beat.kind !== 'dialogue' && beat.kind !== 'thought') {
    return false
  }
  if (beat.speaker_character_id != null && character.character_id != null) {
    return beat.speaker_character_id === character.character_id
  }
  const speaker = (beat.speaker_name ?? '').trim().toLocaleLowerCase('ru-RU').replace(/ё/g, 'е')
  if (!speaker) {
    return false
  }
  const name = character.name.trim().toLocaleLowerCase('ru-RU').replace(/ё/g, 'е')
  return speaker === name
}

type NovelMentionToken = { value: string; index: number }

function tokenizeNovelMentionText(value: string | null | undefined): NovelMentionToken[] {
  const normalized = normalizeNovelCharacterName(value)
  return Array.from(normalized.matchAll(/[a-zа-я0-9]+/giu), (match) => ({
    value: match[0],
    index: match.index ?? 0,
  }))
}

function findLastNovelCharacterMention(
  text: string,
  characters: StoryNovelSceneCharacter[],
): StoryNovelSceneCharacter | null {
  const textTokens = tokenizeNovelMentionText(text)
  if (textTokens.length === 0 || characters.length === 0) {
    return null
  }

  const nameTokensByKey = new Map<string, string[]>()
  const tokenOwnerCount = new Map<string, number>()
  for (const character of characters) {
    const key = normalizeStoryVNCharacterKey(character)
    const nameTokens = tokenizeNovelMentionText(character.name).map((token) => token.value)
    if (!key || nameTokens.length === 0) {
      continue
    }
    nameTokensByKey.set(key, nameTokens)
    for (const token of new Set(nameTokens.filter((item) => item.length >= 3))) {
      tokenOwnerCount.set(token, (tokenOwnerCount.get(token) ?? 0) + 1)
    }
  }

  let focusedCharacter: StoryNovelSceneCharacter | null = null
  let focusedMentionIndex = -1
  for (const character of characters) {
    const key = normalizeStoryVNCharacterKey(character)
    const nameTokens = nameTokensByKey.get(key)
    if (!key || !nameTokens || nameTokens.length === 0) {
      continue
    }

    let lastMentionIndex = -1
    for (let start = 0; start <= textTokens.length - nameTokens.length; start += 1) {
      if (nameTokens.every((token, offset) => textTokens[start + offset]?.value === token)) {
        lastMentionIndex = Math.max(
          lastMentionIndex,
          textTokens[start + nameTokens.length - 1]?.index ?? -1,
        )
      }
    }

    // Card titles often contain a role ("Леди Мия") while prose naturally uses just the
    // personal name ("Мия"). A unique token is safe; shared role words never steal focus.
    for (const token of nameTokens) {
      if (token.length < 3 || tokenOwnerCount.get(token) !== 1) {
        continue
      }
      for (const textToken of textTokens) {
        if (textToken.value === token) {
          lastMentionIndex = Math.max(lastMentionIndex, textToken.index)
        }
      }
    }

    if (lastMentionIndex > focusedMentionIndex) {
      focusedMentionIndex = lastMentionIndex
      focusedCharacter = character
    }
  }
  return focusedCharacter
}

function resolveNovelFocusedCharacter(
  beats: StoryNovelBeat[],
  index: number,
  characters: StoryNovelSceneCharacter[],
): StoryNovelSceneCharacter | null {
  // The current narration page owns focus. Player-move pages and narration without a named
  // participant retain the nearest previous focus instead of falling back to introduction order.
  for (let cursor = index; cursor >= 0; cursor -= 1) {
    const beat = beats[cursor]
    if (!beat || beat.is_player_move) {
      continue
    }
    if (beat.kind === 'dialogue' || beat.kind === 'thought') {
      const speaker = characters.find((character) => beatSpeakerMatchesCharacter(beat, character))
      if (speaker) {
        return speaker
      }
      continue
    }
    const mentionedCharacter = findLastNovelCharacterMention(beat.text, characters)
    if (mentionedCharacter) {
      return mentionedCharacter
    }
  }
  return null
}

// Persistent Visual Novel stage cast. Keeps up to `maxCount` freshest active characters on
// screen — including during narration beats and the player's own move — and, critically, sticks
// each character to the emotion of the last line they actually SPOKE or THOUGHT. A narration
// paragraph keeps a character on stage and can set the emotion of someone who has never spoken,
// but it must never revert an expressed emotion (e.g. a character who just reacted happily must
// stay happy through the following narration instead of snapping back to an older guess).
function resolveNovelStageCast(
  beats: StoryNovelBeat[],
  index: number,
  maxCount: number,
): StoryNovelSceneCharacter[] {
  if (maxCount <= 0 || beats.length === 0) {
    return []
  }
  const clampedIndex = Math.min(Math.max(index, 0), beats.length - 1)
  // Build the active stage from the freshest appearances across pages. A model can emit only
  // the currently discussed person in one VN_CAST; that must not make the two other active
  // characters disappear. Service identities (especially "Рассказчик") are never cast members.
  const presenceByKey = new Map<string, StoryNovelSceneCharacter>()
  const spokenByKey = new Map<string, StoryNovelSceneCharacter>()
  const spriteByKey = new Map<string, StoryNovelSceneCharacter>()
  const recencyKeys: string[] = []
  for (let cursor = clampedIndex; cursor >= 0; cursor -= 1) {
    const beat = beats[cursor]
    if (!beat) {
      continue
    }
    for (const character of beat.scene_characters ?? []) {
      if (isNovelNonCharacterName(character.name)) {
        continue
      }
      const key = normalizeStoryVNCharacterKey(character)
      if (!key) {
        continue
      }
      if (!presenceByKey.has(key)) {
        presenceByKey.set(key, character)
        recencyKeys.push(key)
      }
      if (!spokenByKey.has(key) && beatSpeakerMatchesCharacter(beat, character)) {
        spokenByKey.set(key, character)
      }
      if (!spriteByKey.has(key) && character.sprite_url) {
        spriteByKey.set(key, character)
      }
    }
  }
  const selectedKeys = new Set(recencyKeys.slice(0, maxCount))
  const resolvedByKey = new Map<string, StoryNovelSceneCharacter>()
  for (const key of selectedKeys) {
    const presence = presenceByKey.get(key)
    const spoken = spokenByKey.get(key)
    const sprite = spriteByKey.get(key)
    if (!presence) {
      continue
    }
    const resolvedSprite = sprite ?? spoken ?? presence
    const resolvedGender = inferNovelIncognitoSpriteGender(
      presence.name,
      spoken?.gender ?? sprite?.gender ?? presence.gender,
    )
    const resolvedSpriteUrl = resolvedSprite.sprite_url
      ?? STORY_NOVEL_INCOGNITO_SPRITE_URL_BY_GENDER[resolvedGender]
    const resolved = {
      ...presence,
      emotion: spoken?.emotion ?? presence.emotion,
      sprite_url: resolvedSpriteUrl,
      incognito: resolvedSprite.sprite_url ? resolvedSprite.incognito : true,
      gender: resolvedGender,
    }
    if (resolved.sprite_url) {
      resolvedByKey.set(key, resolved)
    }
  }

  // Preserve introduction order so narration does not randomly reshuffle the stage.
  const ordered: StoryNovelSceneCharacter[] = []
  const placed = new Set<string>()
  for (let cursor = 0; cursor <= clampedIndex && ordered.length < selectedKeys.size; cursor += 1) {
    for (const character of beats[cursor]?.scene_characters ?? []) {
      const key = normalizeStoryVNCharacterKey(character)
      const resolved = resolvedByKey.get(key)
      if (!key || !resolved || placed.has(key)) {
        continue
      }
      placed.add(key)
      ordered.push(resolved)
    }
  }
  if (ordered.length <= 1) {
    return ordered
  }

  const focusedCharacter = resolveNovelFocusedCharacter(beats, clampedIndex, ordered)
  if (!focusedCharacter) {
    return ordered
  }
  const focusedKey = normalizeStoryVNCharacterKey(focusedCharacter)
  return [
    focusedCharacter,
    ...ordered.filter((character) => normalizeStoryVNCharacterKey(character) !== focusedKey),
  ]
}

type VnPlayerMove = { content: string }

// Map every generated assistant turn to the player's action that preceded it, so it can be
// rendered as its own "your move" page. Hidden "continue" turns never get a divider.
function buildVnPlayerMoveMap(
  messages: StoryMessage[],
  hiddenUserMessageIds: number[],
): Map<number, VnPlayerMove> {
  const hidden = new Set(hiddenUserMessageIds)
  const map = new Map<number, VnPlayerMove>()
  let pendingUserMove: VnPlayerMove | null = null
  for (const message of messages) {
    if (message.role === 'user') {
      const content = toStoryText(message.content).replace(/\r\n/g, '\n').trim()
      pendingUserMove =
        !content || content === STORY_CONTINUE_PROMPT || hidden.has(message.id) ? null : { content }
    } else if (message.role === 'assistant') {
      if (message.id > 0 && pendingUserMove) {
        map.set(message.id, pendingUserMove)
      }
      pendingUserMove = null
    }
  }
  return map
}

const VN_PLAYER_MOVE_BEAT_ID_BASE = -2_000_000

function makeVnPlayerMoveBeat(referenceBeat: StoryNovelBeat, move: VnPlayerMove): StoryNovelBeat {
  return {
    id: VN_PLAYER_MOVE_BEAT_ID_BASE - Math.abs(referenceBeat.message_id),
    game_id: referenceBeat.game_id,
    message_id: referenceBeat.message_id,
    // Negative order keeps the divider ahead of the turn's narrator beats.
    order_index: -1,
    kind: 'narration',
    speaker_name: null,
    speaker_character_id: null,
    emotion: null,
    text: move.content,
    sprite_url: null,
    sprite_incognito: false,
    sprite_gender: null,
    scene_characters: [],
    is_player_move: true,
    created_at: referenceBeat.created_at,
    updated_at: referenceBeat.updated_at,
  }
}

// Interleave synthetic "your move" divider beats before each generated turn's beats. Input is
// expected already grouped by message_id (normalizeStoryVNBeats / mergeStoryVNBeatsById sort it).
function applyVnPlayerMoves(
  beats: StoryNovelBeat[],
  playerMoveByMessageId: Map<number, VnPlayerMove>,
): StoryNovelBeat[] {
  if (playerMoveByMessageId.size === 0) {
    return beats
  }
  const result: StoryNovelBeat[] = []
  let lastMessageId: number | null = null
  for (const beat of beats) {
    if (beat.message_id !== lastMessageId) {
      lastMessageId = beat.message_id
      const move = playerMoveByMessageId.get(beat.message_id)
      if (move) {
        result.push(makeVnPlayerMoveBeat(beat, move))
      }
    }
    result.push(beat)
  }
  return result
}

function buildVnDisplayBeats(
  baseBeats: StoryNovelBeat[],
  messages: StoryMessage[],
  hiddenUserMessageIds: number[],
  withPlayerMoves: boolean,
): StoryNovelBeat[] {
  if (!withPlayerMoves || baseBeats.length === 0) {
    return baseBeats
  }
  return applyVnPlayerMoves(baseBeats, buildVnPlayerMoveMap(messages, hiddenUserMessageIds))
}

function isOpeningOnlyVisualNovelSnapshot(
  game: StoryGameSummary,
  messages: StoryMessage[],
): boolean {
  if (game.game_mode !== 'visual_novel') {
    return false
  }
  const openingScene = toStoryText(game.opening_scene).replace(/\r\n/g, '\n').trim()
  if (!openingScene || messages.length !== 1 || messages[0]?.role !== 'assistant') {
    return false
  }
  return toStoryText(messages[0]?.content).replace(/\r\n/g, '\n').trim() === openingScene
}

function mergeStoryVNBeatsById(existingBeats: StoryNovelBeat[], incomingBeats: StoryNovelBeat[]): StoryNovelBeat[] {
  const nextMap = new Map<number, StoryNovelBeat>()
  existingBeats.forEach((beat) => {
    nextMap.set(beat.id, beat)
  })
  incomingBeats.forEach((beat) => {
    nextMap.set(beat.id, beat)
  })
  return [...nextMap.values()].sort(
    (left, right) => left.message_id - right.message_id || left.order_index - right.order_index || left.id - right.id,
  )
}

function normalizeStoryInstructionCardItem(card: StoryInstructionCard): StoryInstructionCard {
  return {
    ...card,
    title: toStoryText(card.title),
    content: toStoryText(card.content),
    is_active: Boolean(card.is_active),
  }
}

function normalizeStoryPlotCardItem(card: StoryPlotCard): StoryPlotCard {
  return {
    ...card,
    title: toStoryText(card.title),
    content: toStoryText(card.content),
    triggers: toStoryStringList(card.triggers),
    memory_turns: typeof card.memory_turns === 'number' && Number.isFinite(card.memory_turns) ? card.memory_turns : null,
  }
}

function normalizeStoryMemoryBlockItem(block: StoryMemoryBlock): StoryMemoryBlock {
  return {
    ...block,
    title: toStoryText(block.title),
    content: toStoryText(block.content),
    token_count: typeof block.token_count === 'number' && Number.isFinite(block.token_count) ? block.token_count : 0,
  }
}

function normalizeStoryWorldCardItem(card: StoryWorldCard): StoryWorldCard {
  return {
    ...card,
    title: toStoryText(card.title),
    content: toStoryText(card.content),
    triggers: toStoryStringList(card.triggers),
    name_color: normalizeStoryCharacterTextColor(card.name_color),
    speech_color: normalizeStoryCharacterTextColor(card.speech_color),
    bubble_color: normalizeStoryCharacterTextColor(card.bubble_color),
    thought_bubble_color: normalizeStoryCharacterTextColor(card.thought_bubble_color),
    memory_turns: typeof card.memory_turns === 'number' && Number.isFinite(card.memory_turns) ? card.memory_turns : null,
  }
}

function normalizeStoryMessages(items: StoryMessage[] | null | undefined): StoryMessage[] {
  return Array.isArray(items) ? items.map((item) => normalizeStoryMessageItem(item)) : []
}

function mergeStoryMessagesById(existingMessages: StoryMessage[], incomingMessages: StoryMessage[]): StoryMessage[] {
  const nextMap = new Map<number, StoryMessage>()
  existingMessages.forEach((message) => {
    nextMap.set(message.id, message)
  })
  incomingMessages.forEach((message) => {
    nextMap.set(message.id, message)
  })
  return [...nextMap.values()].sort((left, right) => left.id - right.id)
}

function normalizeStoryInstructionCards(items: StoryInstructionCard[] | null | undefined): StoryInstructionCard[] {
  return Array.isArray(items) ? items.map((item) => normalizeStoryInstructionCardItem(item)) : []
}

function normalizeStoryPlotCards(items: StoryPlotCard[] | null | undefined): StoryPlotCard[] {
  return Array.isArray(items) ? items.map((item) => normalizeStoryPlotCardItem(item)) : []
}

function normalizeStoryMemoryBlocks(items: StoryMemoryBlock[] | null | undefined): StoryMemoryBlock[] {
  return Array.isArray(items) ? items.map((item) => normalizeStoryMemoryBlockItem(item)) : []
}

function buildOptimisticRawTurnMemoryContent(
  userText: string,
  assistantText: string,
  mainHeroName: string,
): string {
  const normalizedUserText = toStoryText(userText).replace(/\r\n/g, '\n').trim()
  const normalizedAssistantText = toStoryText(assistantText).replace(/\r\n/g, '\n').trim()
  const normalizedMainHeroName = mainHeroName.replace(/\s+/g, ' ').trim() || 'игрок'
  const parts: string[] = []
  if (normalizedUserText) {
    parts.push(`Ход игрока: ${normalizedMainHeroName} (полный текст):\n${normalizedUserText}`)
  }
  if (normalizedAssistantText) {
    parts.push(`Ответ рассказчика (полный текст):\n${normalizedAssistantText}`)
  }
  return parts.join('\n\n').trim()
}

function buildOptimisticRawTurnMemoryTitle(content: string): string {
  const firstContentLine =
    content
      .split('\n')
      .map((line) => line.replace(/\s+/g, ' ').trim())
      .find((line) => line.length > 0) ?? ''
  return firstContentLine.slice(0, 120).trim() || 'Свежий ход'
}

function normalizeStoryWorldCards(items: StoryWorldCard[] | null | undefined): StoryWorldCard[] {
  return Array.isArray(items) ? items.map((item) => normalizeStoryWorldCardItem(item)) : []
}

function resolveMessagesWindowStartIndex(messages: StoryMessage[], assistantTurnsToShow: number): number {
  if (!Array.isArray(messages) || messages.length === 0) {
    return 0
  }
  const normalizedTurns = Math.max(1, Math.trunc(assistantTurnsToShow || 0))
  let assistantsSeen = 0

  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index]
    if (message.role !== 'assistant') {
      continue
    }
    assistantsSeen += 1
    if (assistantsSeen >= normalizedTurns) {
      let startIndex = index
      while (startIndex > 0 && messages[startIndex - 1]?.role === 'user') {
        startIndex -= 1
      }
      return Math.max(startIndex, 0)
    }
  }

  return 0
}

function splitAssistantParagraphs(content: string | null | undefined): string[] {
  const paragraphs = toStoryText(content)
    .replace(/\r\n/g, '\n')
    .split(/\n{2,}/)
    .map((value) => value.trim())
    .filter(Boolean)
  return paragraphs.length > 0 ? paragraphs : ['']
}

function stripStructuredMarkerArtifacts(value: string | null | undefined): string {
  let normalized = toStoryText(value).replace(/\r\n/g, '\n').trim()
  if (!normalized) {
    return ''
  }
  if (!normalized.includes('[[') && !normalized.includes(']]')) {
    return normalized
  }
  normalized = normalized.replace(STRUCTURED_MARKER_ANY_PATTERN, ' ')
  normalized = normalized.replace(STRUCTURED_MARKER_DANGLING_PATTERN, ' ')
  normalized = normalized.replace(/\[\[|\]\]/g, ' ')
  normalized = normalized.replace(/[ \t]+\n/g, '\n')
  normalized = normalized.replace(/\n{3,}/g, '\n\n')
  normalized = normalized
    .split('\n')
    .map((line) => line.replace(/[ \t]{2,}/g, ' ').trim())
    .join('\n')
  return normalized.trim()
}

function splitAssistantParagraphByInlineMarkers(paragraph: string | null | undefined): string[] {
  const normalized = toStoryText(paragraph).replace(/\r\n/g, '\n').trim()
  if (!normalized) {
    return []
  }

  const matches = [...normalized.matchAll(STRUCTURED_MARKER_INLINE_SPLIT_PATTERN)]
  if (matches.length === 0) {
    return [normalized]
  }

  const chunks: string[] = []
  const firstMatchIndex = matches[0]?.index ?? -1
  if (firstMatchIndex < 0) {
    return [normalized]
  }

  const leadingText = normalized.slice(0, firstMatchIndex).trim()
  if (leadingText) {
    chunks.push(leadingText)
  }

  for (let index = 0; index < matches.length; index += 1) {
    const currentMatch = matches[index]
    const markerToken = (currentMatch?.[0] ?? '').trim()
    if (!markerToken) {
      continue
    }
    const markerEnd = (currentMatch?.index ?? 0) + markerToken.length
    const nextMatchStart = matches[index + 1]?.index ?? normalized.length
    const segmentText = normalized.slice(markerEnd, nextMatchStart).trim()
    if (segmentText) {
      chunks.push(`${markerToken} ${segmentText}`.trim())
      continue
    }
    chunks.push(markerToken)
  }

  return chunks.length > 0 ? chunks : [normalized]
}

function isLikelyNarrativeFollowupSentence(sentence: string): boolean {
  const normalizedSentence = sentence.replace(/\s+/g, ' ').trim()
  if (!normalizedSentence) {
    return false
  }
  if (/^["'\u00ab\u00bb\u201e\u201c\u201d]/u.test(normalizedSentence)) {
    return false
  }
  if (/^(?:\u2014|-)\s*\S/u.test(normalizedSentence)) {
    return false
  }
  if (FIRST_OR_SECOND_PERSON_PRONOUN_PATTERN.test(normalizedSentence)) {
    return false
  }
  if (/^[A-Z\u0410-\u042f\u0401][A-Za-z\u0410-\u042f\u0430-\u044f\u0401\u0451-]*(?:\s+[A-Z\u0410-\u042f\u0401][A-Za-z\u0410-\u042f\u0430-\u044f\u0401\u0451-]*)?\s*,/u.test(normalizedSentence)) {
    return false
  }
  return /^[A-Z\u0410-\u042f\u0401][A-Za-z\u0410-\u042f\u0430-\u044f\u0401\u0451-]*(?:\s+[A-Z\u0410-\u042f\u0401][A-Za-z\u0410-\u042f\u0430-\u044f\u0401\u0451-]*)?\s+[a-z\u0430-\u044f\u0451-]+/u.test(
    normalizedSentence,
  )
}

function splitAssistantParagraphByInlinePlainSpeakerLines(paragraph: string | null | undefined): string[] {
  const normalized = toStoryText(paragraph).replace(/\r\n/g, '\n').trim()
  if (!normalized) {
    return []
  }
  if (normalized.includes('[[')) {
    return [normalized]
  }

  const sentences = splitStoryTextIntoSentences(normalized)
  if (sentences.length <= 1) {
    return [normalized]
  }

  const chunks: string[] = []
  const pendingNarrative: string[] = []
  const pendingDialogue: string[] = []
  let sawDialogue = false

  const flushNarrative = () => {
    if (pendingNarrative.length > 0) {
      chunks.push(pendingNarrative.join(' ').trim())
      pendingNarrative.length = 0
    }
  }

  const flushDialogue = () => {
    if (pendingDialogue.length > 0) {
      chunks.push(pendingDialogue.join(' ').trim())
      pendingDialogue.length = 0
    }
  }

  sentences.forEach((sentence) => {
    const plainSpeakerBlock = parsePlainSpeakerAssistantParagraph(sentence)
    if (plainSpeakerBlock && plainSpeakerBlock.type === 'character') {
      flushNarrative()
      flushDialogue()
      pendingDialogue.push(sentence)
      sawDialogue = true
      return
    }

    if (pendingDialogue.length > 0) {
      if (isLikelyNarrativeFollowupSentence(sentence)) {
        flushDialogue()
        pendingNarrative.push(sentence)
      } else {
        pendingDialogue.push(sentence)
      }
      return
    }

    pendingNarrative.push(sentence)
  })

  flushDialogue()
  flushNarrative()

  const normalizedChunks = chunks.filter((chunk) => chunk.trim().length > 0)
  return sawDialogue && normalizedChunks.length > 0 ? normalizedChunks : [normalized]
}

function normalizeAssistantStructuredParagraphs(content: string | null | undefined): string {
  const baseParagraphs = splitAssistantParagraphs(mergeAssistantOrphanStructuredParagraphs(toStoryText(content)))
  const normalizedParagraphs: string[] = []
  baseParagraphs.forEach((paragraph) => {
    splitAssistantParagraphByInlineMarkers(paragraph).forEach((chunk) => {
      normalizedParagraphs.push(...splitAssistantParagraphByInlinePlainSpeakerLines(chunk))
    })
  })
  return normalizedParagraphs.join('\n\n').trim()
}

function normalizeAssistantMarkerKey(value: string): string {
  const normalizedKey = value.toLowerCase().replace(/[\s-]+/g, '_').replace(/ё/g, 'е').trim()
  const compactKey = normalizedKey.replace(/_/g, '')
  const aliasKeyByCompact: Record<string, string> = {
    narrator: 'narrator',
    narration: 'narration',
    narrative: 'narrative',
    'рассказчик': 'narrator',
    'нарратор': 'narrator',
    'повествование': 'narration',
    npc: 'npc',
    'нпс': 'npc',
    'нпк': 'npc',
    npcreplick: 'npc',
    npcreplica: 'npc',
    npcspeech: 'npc',
    npcdialogue: 'npc',
    gg: 'gg',
    'гг': 'gg',
    ggreplick: 'gg',
    ggreplica: 'gg',
    ggspeech: 'gg',
    ggdialogue: 'gg',
    mc: 'mc',
    mainhero: 'mainhero',
    maincharacter: 'mainhero',
    say: 'say',
    speech: 'speech',
    npcthought: 'npc_thought',
    npcthink: 'npc_thought',
    ggthought: 'gg_thought',
    ggthink: 'gg_thought',
    thought: 'thought',
    think: 'think',
    'нпсмысль': 'npc_thought',
    'нпсмысли': 'npc_thought',
    'нпкмысль': 'npc_thought',
    'нпкмысли': 'npc_thought',
    'ггмысль': 'gg_thought',
    'ггмысли': 'gg_thought',
  }
  return aliasKeyByCompact[compactKey] ?? normalizedKey
}

function resolveMainHeroDisplayName(rawMainHeroName: string | null | undefined): string {
  const normalizedMainHeroName = (rawMainHeroName ?? '').replace(/\s+/g, ' ').trim()
  return normalizedMainHeroName || MAIN_HERO_FALLBACK_NAME
}

function normalizeMainHeroInlineFallbackName(rawValue: string | null | undefined): string {
  const normalizedValue = (rawValue ?? '').replace(/\s+/g, ' ').trim()
  if (!normalizedValue) {
    return MAIN_HERO_FALLBACK_NAME
  }
  return normalizedValue.toLowerCase().replace(/ё/g, 'е') === 'главный герой'
    ? MAIN_HERO_FALLBACK_NAME
    : normalizedValue
}

function replaceMainHeroInlineTags(value: string, rawMainHeroName: string | null | undefined): string {
  if (!value || !value.includes('[[')) {
    return value
  }
  const normalizedMainHeroName = (rawMainHeroName ?? '').replace(/\s+/g, ' ').trim()
  return value.replace(MAIN_HERO_INLINE_TAG_PATTERN, (_fullMatch, inlineFallbackName: string | undefined) => {
    return normalizedMainHeroName || normalizeMainHeroInlineFallbackName(inlineFallbackName)
  })
}

function mergeAssistantOrphanStructuredParagraphs(content: string): string {
  const paragraphs = splitAssistantParagraphs(content)
  const mergedParagraphs: string[] = []
  let pendingMarker = ''

  paragraphs.forEach((paragraph) => {
    const lines = paragraph
      .replace(/\r\n/g, '\n')
      .split('\n')
      .map((value) => value.trim())
      .filter(Boolean)
    if (lines.length === 0) {
      return
    }

    const firstLine = lines[0] ?? ''
    if (pendingMarker) {
      if (!STRUCTURED_MARKER_LINE_START_PATTERN.test(firstLine)) {
        mergedParagraphs.push(`${pendingMarker} ${lines.join(' ')}`.trim())
        pendingMarker = ''
        return
      }
      pendingMarker = ''
    }

    if (STRUCTURED_MARKER_STANDALONE_PATTERN.test(firstLine)) {
      if (lines.length === 1) {
        pendingMarker = firstLine
        return
      }
      const trailingText = lines.slice(1).join(' ').trim()
      if (!trailingText) {
        pendingMarker = firstLine
        return
      }
      if (STRUCTURED_MARKER_LINE_START_PATTERN.test(trailingText)) {
        mergedParagraphs.push(trailingText)
        return
      }
      mergedParagraphs.push(`${firstLine} ${trailingText}`.trim())
      return
    }

    mergedParagraphs.push(lines.join('\n'))
  })

  return mergedParagraphs.join('\n\n').trim()
}

function normalizeAssistantSpeakerName(rawValue: string | null | undefined): string {
  return (rawValue ?? '')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/^["'«„]+|["'»”]+$/g, '')
    .trim()
    .replace(/^[\s.,:;!?()[\]-]+|[\s.,:;!?()[\]-]+$/gu, '')
    .trim()
}

function isLikelyAssistantSpeakerName(rawValue: string | null | undefined): boolean {
  const normalized = normalizeAssistantSpeakerName(rawValue)
  if (!normalized) {
    return false
  }

  if (ASSISTANT_SPEAKER_NAME_DISALLOWED_PUNCTUATION_PATTERN.test(normalized)) {
    return false
  }

  const words = normalized.split(/\s+/).filter(Boolean)
  if (words.length === 0 || words.length > ASSISTANT_SPEAKER_NAME_MAX_WORDS) {
    return false
  }

  if (words.some((word) => !ASSISTANT_SPEAKER_NAME_TOKEN_PATTERN.test(word))) {
    return false
  }

  return !words.slice(1).some((word) => {
    const firstCharacter = word.charAt(0)
    return firstCharacter === firstCharacter.toLowerCase() && ASSISTANT_SPEAKER_NAME_VERB_PATTERN.test(word.toLowerCase())
  })
}

function stripLeadingStructuredMarkerLines(value: string | null | undefined): string {
  let normalized = toStoryText(value).replace(/\r\n/g, '\n').trim()
  while (true) {
    const nextValue = normalized.replace(
      /^\[\[\s*[^\]:]+?(?:\s*:\s*[^\]]+?)?\s*\]\]\s*(?:\n+\s*|\s+)/u,
      '',
    ).trim()
    if (nextValue === normalized) {
      return normalized
    }
    normalized = nextValue
  }
}

type AssistantMarkerKind = 'narrative' | 'speech' | 'thought'

function resolveAssistantMarkerKind(
  markerKey: string,
): AssistantMarkerKind | null {
  const compact = markerKey.replace(/_/g, '')
  if (compact === 'narrator' || compact === 'narration' || compact === 'narrative') {
    return 'narrative'
  }
  if (
    compact === 'npc' ||
    compact === 'gg' ||
    compact === 'mc' ||
    compact === 'mainhero' ||
    compact === 'say' ||
    compact === 'speech'
  ) {
    return 'speech'
  }
  if (compact === 'npcthought' || compact === 'ggthought' || compact === 'thought' || compact === 'think') {
    return 'thought'
  }
  return null
}

function resolveAssistantBareSpeakerMarkerName(
  rawMarkerName: string,
  rawSpeakerName: string | null | undefined,
): string | null {
  const explicitSpeakerName = normalizeAssistantSpeakerName(rawSpeakerName)
  if (explicitSpeakerName) {
    return null
  }

  const speakerName = normalizeAssistantSpeakerName(rawMarkerName)
  if (!speakerName || !isLikelyAssistantSpeakerName(speakerName)) {
    return null
  }

  const markerKind = resolveAssistantMarkerKind(normalizeAssistantMarkerKey(speakerName))
  if (markerKind) {
    return null
  }

  return speakerName
}

type AssistantTagDescriptor = {
  kind: AssistantMarkerKind
  defaultSpeakerName: string | null
}

function resolveAssistantTagKind(markerKey: string): AssistantTagDescriptor | null {
  const compact = markerKey.replace(/_/g, '')
  if (compact === 'narrator' || compact === 'narration' || compact === 'narrative') {
    return {
      kind: 'narrative',
      defaultSpeakerName: null,
    }
  }
  if (
    compact === 'gg' ||
    compact === 'ggreplick' ||
    compact === 'ggreplica' ||
    compact === 'ggspeech' ||
    compact === 'ggdialogue'
  ) {
    return {
      kind: 'speech',
      defaultSpeakerName: 'ГГ',
    }
  }
  if (compact === 'ggthought' || compact === 'ggthink') {
    return {
      kind: 'thought',
      defaultSpeakerName: 'ГГ',
    }
  }
  if (
    compact === 'npc' ||
    compact === 'npcreplick' ||
    compact === 'npcreplica' ||
    compact === 'npcspeech' ||
    compact === 'npcdialogue'
  ) {
    return {
      kind: 'speech',
      defaultSpeakerName: GENERIC_DIALOGUE_SPEAKER_DEFAULT,
    }
  }
  if (compact === 'npcthought' || compact === 'npcthink') {
    return {
      kind: 'thought',
      defaultSpeakerName: GENERIC_DIALOGUE_SPEAKER_DEFAULT,
    }
  }
  return null
}

function parseStructuredAssistantParagraph(paragraph: string | null | undefined): AssistantMessageBlock | null {
  const normalized = toStoryText(paragraph).replace(/\r\n/g, '\n').trim()
  if (!normalized) {
    return null
  }

  const markerMatch = normalized.match(STRUCTURED_MARKER_START_PATTERN)
  if (!markerMatch) {
    return null
  }

  const rawMarkerName = markerMatch[1]?.trim() ?? ''
  const rawSpeakerName = markerMatch[2]?.trim() ?? ''
  let markerKind = resolveAssistantMarkerKind(normalizeAssistantMarkerKey(rawMarkerName))
  let speakerName = normalizeAssistantSpeakerName(rawSpeakerName)
  if (!markerKind) {
    speakerName = resolveAssistantBareSpeakerMarkerName(rawMarkerName, rawSpeakerName) ?? ''
    if (!speakerName) {
      return null
    }
    markerKind = 'speech'
  }

  const bodyText = stripStructuredMarkerArtifacts(stripLeadingStructuredMarkerLines(markerMatch[3].trim()))
  if (!bodyText) {
    return null
  }

  if (markerKind === 'narrative') {
    return { type: 'narrative', text: bodyText }
  }

  if (!speakerName || (rawSpeakerName && !isLikelyAssistantSpeakerName(speakerName))) {
    return null
  }

  return {
    type: 'character',
    speakerName,
    text: bodyText,
    delivery: markerKind === 'thought' ? 'thought' : 'speech',
  }
}

function parsePlainSpeakerAssistantParagraph(paragraph: string | null | undefined): AssistantMessageBlock | null {
  const normalized = toStoryText(paragraph).replace(/\r\n/g, '\n').trim()
  if (!normalized) {
    return null
  }

  const speakerMatch = normalized.match(PLAIN_SPEAKER_LINE_PATTERN)
  if (!speakerMatch) {
    return null
  }

  const speakerName = normalizeAssistantSpeakerName(speakerMatch[1])
  if (!speakerName || !isLikelyAssistantSpeakerName(speakerName)) {
    return null
  }

  const bodyText = stripStructuredMarkerArtifacts(speakerMatch[3]?.trim() ?? '')
  if (!bodyText) {
    return null
  }

  const speakerMarkerKind = resolveAssistantMarkerKind(normalizeAssistantMarkerKey(speakerName))
  if (speakerMarkerKind === 'narrative') {
    return { type: 'narrative', text: bodyText }
  }

  if (isLikelyNarrativeSpeechLine(bodyText, speakerName)) {
    return null
  }

  return {
    type: 'character',
    speakerName,
    text: bodyText,
    delivery: speakerMatch[2] ? 'thought' : 'speech',
  }
}

function parseTaggedAssistantParagraph(paragraph: string | null | undefined): AssistantMessageBlock | null {
  const normalized = toStoryText(paragraph).replace(/\r\n/g, '\n').trim()
  if (!normalized) {
    return null
  }

  const tagMatch = normalized.match(STRUCTURED_TAG_PATTERN)
  if (!tagMatch) {
    return null
  }

  const openingTagKey = normalizeAssistantMarkerKey(tagMatch[1])
  const closingTagKey = normalizeAssistantMarkerKey(tagMatch[4])
  if (!openingTagKey || openingTagKey !== closingTagKey) {
    return null
  }

  const tagDescriptor = resolveAssistantTagKind(openingTagKey)
  if (!tagDescriptor) {
    return null
  }

  const bodyText = stripStructuredMarkerArtifacts(stripLeadingStructuredMarkerLines(tagMatch[3].trim()))
  if (!bodyText) {
    return null
  }

  if (tagDescriptor.kind === 'narrative') {
    return { type: 'narrative', text: bodyText }
  }

  const rawSpeakerName = tagMatch[2]?.trim() ?? ''
  const explicitSpeakerName = normalizeAssistantSpeakerName(rawSpeakerName)
  if (explicitSpeakerName && !isLikelyAssistantSpeakerName(explicitSpeakerName)) {
    return null
  }
  const speakerName = explicitSpeakerName || tagDescriptor.defaultSpeakerName || GENERIC_DIALOGUE_SPEAKER_DEFAULT
  if (!speakerName) {
    return null
  }

  return {
    type: 'character',
    speakerName,
    text: bodyText,
    delivery: tagDescriptor.kind === 'thought' ? 'thought' : 'speech',
  }
}

function parseTaggedAssistantContent(content: string | null | undefined): AssistantMessageBlock[] | null {
  const normalized = toStoryText(content).replace(/\r\n/g, '\n').trim()
  if (!normalized) {
    return null
  }

  const tagPattern = /<\s*([A-Za-z_ -]+)(?:\s*:\s*([^>]+?))?\s*>([\s\S]*?)<\/\s*([A-Za-z_ -]+)\s*>/giu
  const blocks: AssistantMessageBlock[] = []
  let hasTaggedBlocks = false
  let cursor = 0

  const pushNarrativeFragments = (value: string) => {
    const fragments = splitAssistantParagraphs(value)
    fragments.forEach((fragment) => {
      const structuredBlock = parseStructuredAssistantParagraph(fragment)
      if (structuredBlock) {
        blocks.push(structuredBlock)
        return
      }
      const plainSpeakerBlock = parsePlainSpeakerAssistantParagraph(fragment)
      if (plainSpeakerBlock) {
        blocks.push(plainSpeakerBlock)
        return
      }
      const text = stripStructuredMarkerArtifacts(fragment)
      if (!text) {
        return
      }
      blocks.push({ type: 'narrative', text })
    })
  }

  for (const match of normalized.matchAll(tagPattern)) {
    const fullMatch = match[0]
    const matchIndex = match.index ?? -1
    if (matchIndex < 0) {
      return null
    }

    const between = normalized.slice(cursor, matchIndex)
    if (between.trim().length > 0) {
      pushNarrativeFragments(between)
    }

    const parsedBlock = parseTaggedAssistantParagraph(fullMatch)
    if (!parsedBlock) {
      return null
    }
    blocks.push(parsedBlock)
    hasTaggedBlocks = true
    cursor = matchIndex + fullMatch.length
  }

  const tail = normalized.slice(cursor)
  if (tail.trim().length > 0) {
    pushNarrativeFragments(tail)
  }

  if (!hasTaggedBlocks || blocks.length === 0) {
    return null
  }

  return blocks
}

function splitLooseAssistantParagraphFragments(paragraph: string | null | undefined): string[] {
  const normalized = toStoryText(paragraph).replace(/\r\n/g, '\n').trim()
  if (!normalized) {
    return []
  }
  const fragments = normalized
    .replace(LOOSE_ASSISTANT_CUE_BREAK_PATTERN, '$1\n')
    .split('\n')
    .map((value) => value.trim())
    .filter(Boolean)
  return fragments.length > 0 ? fragments : [normalized]
}

function stripLooseDialogueWrapper(value: string | null | undefined): string {
  return stripStructuredMarkerArtifacts(value)
    .replace(/^\s*(?:\u2014|-)\s*/u, '')
    .replace(/^\s*["\u00ab\u201e\u201c]+/u, '')
    .replace(/["\u00bb\u201d]+\s*$/u, '')
    .trim()
}

function resolveLooseThoughtSpeakerName(value: string): string {
  return FIRST_OR_SECOND_PERSON_PRONOUN_PATTERN.test(value)
    ? MAIN_HERO_FALLBACK_NAME
    : GENERIC_DIALOGUE_SPEAKER_DEFAULT
}

function parseLooseAssistantFragment(fragment: string | null | undefined): AssistantMessageBlock | null {
  const normalized = toStoryText(fragment).replace(/\r\n/g, '\n').trim()
  if (!normalized) {
    return null
  }

  const thoughtMatch = normalized.match(LOOSE_THOUGHT_LINE_PATTERN)
  if (thoughtMatch) {
    const bodyText = stripLooseDialogueWrapper(thoughtMatch[1])
    if (!bodyText) {
      return null
    }
    return {
      type: 'character',
      speakerName: resolveLooseThoughtSpeakerName(bodyText),
      text: bodyText,
      delivery: 'thought',
    }
  }

  const dashDialogueMatch = normalized.match(LOOSE_DIALOGUE_DASH_LINE_PATTERN)
  if (dashDialogueMatch) {
    const bodyText = stripLooseDialogueWrapper(dashDialogueMatch[1])
    if (!bodyText) {
      return null
    }
    return {
      type: 'character',
      speakerName: GENERIC_DIALOGUE_SPEAKER_DEFAULT,
      text: bodyText,
      delivery: 'speech',
    }
  }

  const quotedDialogueMatch = normalized.match(LOOSE_DIALOGUE_QUOTE_LINE_PATTERN)
  if (quotedDialogueMatch) {
    const bodyText = stripLooseDialogueWrapper(quotedDialogueMatch[1])
    if (!bodyText) {
      return null
    }
    return {
      type: 'character',
      speakerName: GENERIC_DIALOGUE_SPEAKER_DEFAULT,
      text: bodyText,
      delivery: 'speech',
    }
  }

  return null
}

function parseLooseAssistantParagraph(paragraph: string | null | undefined): AssistantMessageBlock[] | null {
  const fragments = splitLooseAssistantParagraphFragments(paragraph)
  if (fragments.length === 0) {
    return null
  }

  const blocks: AssistantMessageBlock[] = []
  let hasCharacterBlock = false
  const pushBlock = (block: AssistantMessageBlock) => {
    const previousBlock = blocks[blocks.length - 1]
    if (!previousBlock) {
      blocks.push(block)
      return
    }
    if (previousBlock.type === 'narrative' && block.type === 'narrative') {
      previousBlock.text = `${previousBlock.text}\n${block.text}`.trim()
      return
    }
    if (
      previousBlock.type === 'character' &&
      block.type === 'character' &&
      previousBlock.delivery === block.delivery &&
      previousBlock.speakerName === block.speakerName
    ) {
      previousBlock.text = `${previousBlock.text}\n${block.text}`.trim()
      return
    }
    blocks.push(block)
  }

  fragments.forEach((fragment) => {
    const taggedBlock = parseTaggedAssistantParagraph(fragment)
    if (taggedBlock) {
      hasCharacterBlock = hasCharacterBlock || taggedBlock.type === 'character'
      pushBlock(taggedBlock)
      return
    }

    const structuredBlock = parseStructuredAssistantParagraph(fragment)
    if (structuredBlock) {
      hasCharacterBlock = hasCharacterBlock || structuredBlock.type === 'character'
      pushBlock(structuredBlock)
      return
    }

    const plainSpeakerBlock = parsePlainSpeakerAssistantParagraph(fragment)
    if (plainSpeakerBlock) {
      hasCharacterBlock = true
      pushBlock(plainSpeakerBlock)
      return
    }

    const looseBlock = parseLooseAssistantFragment(fragment)
    if (looseBlock) {
      hasCharacterBlock = true
      pushBlock(looseBlock)
      return
    }

    const cleanedText = stripStructuredMarkerArtifacts(fragment)
    if (!cleanedText) {
      return
    }
    pushBlock({ type: 'narrative', text: cleanedText })
  })

  return hasCharacterBlock && blocks.length > 0 ? blocks : null
}

function parseAssistantMessageBlocks(content: string | null | undefined): AssistantMessageBlock[] {
  const normalized = normalizeAssistantStructuredParagraphs(content)
  if (!normalized) {
    return []
  }

  const taggedContentBlocks = parseTaggedAssistantContent(normalized)
  if (taggedContentBlocks) {
    return taggedContentBlocks
  }

  const blocks: AssistantMessageBlock[] = []
  splitAssistantParagraphs(normalized).forEach((paragraph) => {
    const taggedBlock = parseTaggedAssistantParagraph(paragraph)
    if (taggedBlock) {
      blocks.push(taggedBlock)
      return
    }

    const structuredBlock = parseStructuredAssistantParagraph(paragraph)
    if (structuredBlock) {
      blocks.push(structuredBlock)
      return
    }

    const plainSpeakerBlock = parsePlainSpeakerAssistantParagraph(paragraph)
    if (plainSpeakerBlock) {
      blocks.push(plainSpeakerBlock)
      return
    }

    const looseBlocks = parseLooseAssistantParagraph(paragraph)
    if (looseBlocks) {
      blocks.push(...looseBlocks)
      return
    }

    // Strict mode: any unmarked paragraph is treated as narration only.
    const cleanedParagraph = stripStructuredMarkerArtifacts(paragraph)
    if (cleanedParagraph) {
      blocks.push({ type: 'narrative', text: cleanedParagraph })
    }
  })
  return blocks
    .map((block) => {
      const cleanedText = stripStructuredMarkerArtifacts(block.text)
      if (!cleanedText) {
        return null
      }
      if (block.type === 'character') {
        const cleanedSpeakerName = stripStructuredMarkerArtifacts(block.speakerName).replace(/\s+/g, ' ').trim()
        if (!cleanedSpeakerName) {
          return { type: 'narrative', text: cleanedText } as AssistantMessageBlock
        }
        return {
          ...block,
          speakerName: cleanedSpeakerName,
          text: cleanedText,
        }
      }
      return {
        ...block,
        text: cleanedText,
      }
    })
    .filter((block): block is AssistantMessageBlock => block !== null)
}

function isLikelyNarrativeSpeechLine(text: string, speakerName: string): boolean {
  const normalizedText = text.replace(/\s+/g, ' ').trim()
  if (!normalizedText) {
    return true
  }
  if (
    DIALOGUE_QUOTE_CUE_PATTERN.test(normalizedText) ||
    DIALOGUE_DASH_START_CUE_PATTERN.test(normalizedText) ||
    DIALOGUE_DASH_AFTER_PUNCT_CUE_PATTERN.test(normalizedText) ||
    FIRST_OR_SECOND_PERSON_PRONOUN_PATTERN.test(normalizedText)
  ) {
    return false
  }

  const normalizedLine = normalizedText.replace(/^[\s"'.,:;!?()[\]\u00ab\u00bb\u201e\u201c\u201d-]+/u, '').toLowerCase()
  if (THIRD_PERSON_NARRATIVE_START_PATTERN.test(normalizedLine)) {
    return true
  }

  const normalizedSpeakerName = speakerName.replace(/\s+/g, ' ').trim().toLowerCase()
  return Boolean(normalizedSpeakerName) && normalizedLine.startsWith(`${normalizedSpeakerName} `)
}

function serializeAssistantMessageBlock(block: AssistantMessageBlock): string {
  const normalizedText = stripStructuredMarkerArtifacts(toStoryText(block.text)).replace(/\r\n/g, '\n').trim()
  if (!normalizedText) {
    return ''
  }

  if (block.type === 'narrative') {
    return normalizedText
  }

  const speakerName = stripStructuredMarkerArtifacts(block.speakerName).replace(/\s+/g, ' ').trim() || GENERIC_DIALOGUE_SPEAKER_DEFAULT
  const markerName = block.delivery === 'thought' ? 'NPC_THOUGHT' : 'NPC'
  return `[[${markerName}:${speakerName}]] ${normalizedText}`
}

function serializeAssistantMessageBlocks(blocks: AssistantMessageBlock[]): string {
  return blocks
    .map((block) => serializeAssistantMessageBlock(block))
    .filter((value) => value.length > 0)
    .join('\n\n')
    .trim()
}

function buildAssistantMessageContentWithEditedBlock(
  content: string | null | undefined,
  sourceIndex: number,
  nextText: string,
): string | null {
  const blocks = parseAssistantMessageBlocks(content)
  if (blocks.length === 0 || sourceIndex < 0 || sourceIndex >= blocks.length) {
    return null
  }

  const normalizedText = nextText.replace(/\r\n/g, '\n').trim()
  const nextBlocks = normalizedText
    ? blocks.map((block, index) => (index === sourceIndex ? { ...block, text: normalizedText } : block))
    : blocks.filter((_, index) => index !== sourceIndex)
  const serialized = serializeAssistantMessageBlocks(nextBlocks)
  return serialized
}

function isMainHeroThoughtSpeakerName(rawSpeakerName: string, mainHeroName: string): boolean {
  const heroAliases = new Set<string>()
  ;[mainHeroName, MAIN_HERO_FALLBACK_NAME, ...MAIN_HERO_SPEAKER_ALIASES].forEach((value) => {
    buildCharacterAliases(value).forEach((alias) => heroAliases.add(alias))
  })
  if (heroAliases.size === 0) {
    return false
  }
  return extractSpeakerLookupValues(rawSpeakerName).some((value) => {
    const normalizedValue = normalizeCharacterIdentity(value)
    return normalizedValue.length > 0 && heroAliases.has(normalizedValue)
  })
}

function filterAssistantMessageBlocksForDisplay(
  blocks: AssistantMessageBlock[],
  options: {
    mainHeroName: string
    showNpcThoughts: boolean
  },
): AssistantMessageDisplayBlock[] {
  const { mainHeroName, showNpcThoughts } = options
  const displayBlocks: AssistantMessageDisplayBlock[] = []
  blocks.forEach((block, sourceIndex) => {
    if (block.type !== 'character' || block.delivery !== 'thought') {
      displayBlocks.push({ ...block, sourceIndex })
      return
    }
    if (isMainHeroThoughtSpeakerName(block.speakerName, mainHeroName)) {
      return
    }
    if (showNpcThoughts) {
      displayBlocks.push({ ...block, sourceIndex })
    }
  })
  return displayBlocks
}

type StreamingAssistantTextStore = {
  subscribe: (listener: () => void) => () => void
  getText: (messageId: number) => string
  setText: (messageId: number, text: string) => void
  clear: (messageId?: number) => void
}

function createStreamingAssistantTextStore(): StreamingAssistantTextStore {
  const listeners = new Set<() => void>()
  let activeMessageId: number | null = null
  let activeText = ''

  const notify = () => {
    Array.from(listeners).forEach((listener) => listener())
  }

  return {
    subscribe: (listener) => {
      listeners.add(listener)
      return () => listeners.delete(listener)
    },
    getText: (messageId) => (messageId === activeMessageId ? activeText : ''),
    setText: (messageId, text) => {
      const nextText = String(text ?? '')
      if (activeMessageId === messageId && activeText === nextText) {
        return
      }
      activeMessageId = messageId
      activeText = nextText
      notify()
    },
    clear: (messageId) => {
      if (activeMessageId === null) {
        return
      }
      if (typeof messageId === 'number' && activeMessageId !== messageId) {
        return
      }
      activeMessageId = null
      activeText = ''
      notify()
    },
  }
}

function MoriusGenerationOrb({
  size = 22,
  onStop,
}: {
  size?: number
  onStop?: () => void
}) {
  const clickable = Boolean(onStop)
  return (
    <Box
      component="span"
      className="morius-gen-orb"
      onClick={
        onStop
          ? (event) => {
              event.stopPropagation()
              onStop()
            }
          : undefined
      }
      title={clickable ? 'Нажмите, чтобы остановить генерацию' : undefined}
      role={clickable ? 'button' : undefined}
      aria-label={clickable ? 'Остановить генерацию' : undefined}
      sx={{ width: size, height: size, cursor: clickable ? 'pointer' : 'default' }}
    >
      <Box component="span" className="morius-gen-orb__halo" aria-hidden="true" />
      <Box component="span" className="morius-gen-orb__ring" aria-hidden="true" />
      <Box component="span" className="morius-gen-orb__core" aria-hidden="true" />
    </Box>
  )
}

function MoriusThinkingIndicator({ onStop }: { onStop?: () => void }) {
  return (
    <Stack spacing={0.55} sx={{ alignItems: 'flex-start', px: 0.05, py: 0.1 }}>
      <Stack direction="row" alignItems="center" spacing={1.15}>
        <MoriusGenerationOrb size={22} onStop={onStop} />
        <Typography
          className="morius-think-shimmer"
          sx={{ fontSize: '18px', fontWeight: 600, lineHeight: 1.1, letterSpacing: 0.1 }}
        >
          Смотрим, что было дальше
        </Typography>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: '4px', pl: '2px' }}>
          <Box className="morius-think-dot" />
          <Box className="morius-think-dot" sx={{ animationDelay: '0.18s' }} />
          <Box className="morius-think-dot" sx={{ animationDelay: '0.36s' }} />
        </Box>
      </Stack>
      <Typography sx={{ color: '#586074', fontSize: '12.5px', lineHeight: 1.25, pl: '34px' }}>
        можно прервать генерацию кнопкой в строке ввода ниже
      </Typography>
    </Stack>
  )
}

type StreamingAssistantMessageContentProps = {
  messageId: number
  store: StreamingAssistantTextStore
  mainHeroName: string
  showNpcThoughts: boolean
  onStopGeneration?: () => void
  assistantReplyTextColor: string
  assistantSpeakerLabelColor: string
  assistantThoughtLabelColor: string
  assistantThoughtTextColor: string
  isGrayTheme: boolean
  storyHistoryTextSx: Record<string, string | number>
  renderPreviewableCharacterAvatar: (options: {
    avatarUrl: string | null
    previewUrl?: string | null
    avatarScale?: number
    fallbackLabel: string
    size?: number
    profileCard?: StoryWorldCard | null
    profileCharacter?: StoryCharacter | null
    avatarBgColor?: string
  }) => ReactNode
  resolveDialogueAvatar: (speakerName: string) => string | null
  resolveDialogueAvatarPreview: (speakerName: string) => string | null
  resolveDialogueSpeakerEntry: (speakerName: string) => SpeakerAvatarEntry | null
  resolveDialogueSpeakerName: (speakerName: string, dialogueText: string, nearbyNarrativeText?: string) => string
}

function StreamingAssistantMessageContent({
  messageId,
  store,
  mainHeroName,
  showNpcThoughts,
  onStopGeneration,
  assistantReplyTextColor,
  assistantSpeakerLabelColor,
  assistantThoughtLabelColor,
  assistantThoughtTextColor,
  isGrayTheme,
  storyHistoryTextSx,
  renderPreviewableCharacterAvatar,
  resolveDialogueAvatar,
  resolveDialogueAvatarPreview,
  resolveDialogueSpeakerEntry,
  resolveDialogueSpeakerName,
}: StreamingAssistantMessageContentProps) {
  const streamingText = useSyncExternalStore(
    store.subscribe,
    () => store.getText(messageId),
    () => '',
  )
  const blocks = useMemo(() => {
    const resolvedContent = replaceMainHeroInlineTags(streamingText, mainHeroName)
    return filterAssistantMessageBlocksForDisplay(parseAssistantMessageBlocks(resolvedContent), {
      mainHeroName,
      showNpcThoughts,
    })
  }, [mainHeroName, showNpcThoughts, streamingText])

  if (blocks.length === 0) {
    return <MoriusThinkingIndicator onStop={onStopGeneration} />
  }

  return (
    <Box sx={{ position: 'relative', pl: '37px' }}>
      <Box sx={{ position: 'absolute', left: '1px', top: '4px', pointerEvents: 'none' }}>
        <MoriusGenerationOrb size={16} />
      </Box>
      {blocks.map((block, index) => {
        const shouldShowStreamingCaret = index === blocks.length - 1
        if (block.type === 'character') {
          const nearbyNarrativeContext = blocks
            .slice(Math.max(0, index - 3), Math.min(blocks.length, index + 4))
            .filter((candidate) => candidate.type === 'narrative')
            .map((candidate) => candidate.text)
            .join('\n')
          const resolvedSpeakerName = resolveDialogueSpeakerName(
            block.speakerName,
            block.text,
            nearbyNarrativeContext,
          )
          const speakerAvatar = resolveDialogueAvatar(resolvedSpeakerName)
          const speakerEntry = resolveDialogueSpeakerEntry(resolvedSpeakerName)
          const isThoughtBlock = block.delivery === 'thought'
          const speakerLabelColor = resolveSpeakerNameColor(
            speakerEntry,
            isThoughtBlock ? assistantThoughtLabelColor : assistantSpeakerLabelColor,
          )
          const speakerTextColor = resolveSpeakerSpeechColor(
            speakerEntry,
            isGrayTheme
              ? assistantReplyTextColor
              : isThoughtBlock
                ? assistantThoughtTextColor
                : 'var(--morius-title-text)',
          )
          const bubbleColor = resolveSpeakerBubbleColor(speakerEntry, isThoughtBlock)
          const bubbleBg = `color-mix(in srgb, ${bubbleColor} 16%, transparent)`
          return (
            <Stack
              key={`${messageId}-${index}-stream-character`}
              spacing={0.4}
              sx={{ px: 0.05, py: 0.45 }}
            >
              <Stack direction="row" spacing={0.75} alignItems="center">
                {renderPreviewableCharacterAvatar({
                  avatarUrl: speakerAvatar,
                  previewUrl: resolveDialogueAvatarPreview(resolvedSpeakerName),
                  fallbackLabel: resolvedSpeakerName,
                  size: ASSISTANT_DIALOGUE_AVATAR_SIZE,
                  profileCard: speakerEntry?.card ?? null,
                  profileCharacter: speakerEntry?.character ?? null,
                  avatarBgColor: bubbleColor,
                })}
                <Stack direction="row" spacing={0.55} alignItems="center" sx={{ minWidth: 0 }}>
                  <Typography
                    noWrap
                    sx={{
                      color: speakerLabelColor,
                      fontSize: '0.84rem',
                      lineHeight: 1.2,
                      fontWeight: 700,
                      letterSpacing: 0.1,
                    }}
                  >
                    {resolvedSpeakerName}
                  </Typography>
                  <Typography
                    sx={{
                      color: 'var(--morius-text-secondary)',
                      fontSize: '0.65rem',
                      fontWeight: 800,
                      letterSpacing: '0.08em',
                      flexShrink: 0,
                    }}
                  >
                    ·{isThoughtBlock ? ' В ГОЛОВЕ' : ' РЕПЛИКА'}
                  </Typography>
                </Stack>
              </Stack>
              <Box
                sx={{
                  ml: `${ASSISTANT_DIALOGUE_AVATAR_SIZE + 6}px`,
                  borderLeft: `2.5px solid ${bubbleColor}`,
                  backgroundColor: bubbleBg,
                  borderRadius: '0 8px 8px 0',
                  px: 1.5,
                  py: 0.85,
                }}
              >
                <Box
                  component="div"
                  sx={{
                    color: speakerTextColor,
                    lineHeight: 1.54,
                    fontSize: { xs: '1rem', md: '1.08rem' },
                    ...storyHistoryTextSx,
                    fontStyle: isThoughtBlock ? 'italic' : 'normal',
                    whiteSpace: 'pre-wrap',
                  }}
                >
                  {block.text}
                  {shouldShowStreamingCaret ? (
                    <Box component="span" className={STREAMING_CARET_CLASS_NAME} aria-hidden="true" />
                  ) : null}
                </Box>
              </Box>
            </Stack>
          )
        }

        return (
          <Box
            key={`${messageId}-${index}-stream`}
            sx={{
              px: 0.05,
              py: 0.05,
            }}
          >
            <Box
              component="div"
              sx={{
                color: assistantReplyTextColor,
                lineHeight: 1.58,
                fontSize: { xs: '1.02rem', md: '1.12rem' },
                ...storyHistoryTextSx,
                whiteSpace: 'pre-wrap',
              }}
            >
              {block.text}
              {shouldShowStreamingCaret ? (
                <Box component="span" className={STREAMING_CARET_CLASS_NAME} aria-hidden="true" />
              ) : null}
            </Box>
          </Box>
        )
      })}
    </Box>
  )
}


const LATIN_TO_CYRILLIC_NAME_DIGRAPHS: Array<[string, string]> = [
  ['shch', 'щ'],
  ['sch', 'щ'],
  ['yo', 'ё'],
  ['yu', 'ю'],
  ['ya', 'я'],
  ['zh', 'ж'],
  ['kh', 'х'],
  ['ts', 'ц'],
  ['ch', 'ч'],
  ['sh', 'ш'],
  ['ye', 'е'],
]

const LATIN_TO_CYRILLIC_NAME_MAP: Record<string, string> = {
  a: 'а',
  b: 'б',
  c: 'к',
  d: 'д',
  e: 'е',
  f: 'ф',
  g: 'г',
  h: 'х',
  i: 'и',
  j: 'й',
  k: 'к',
  l: 'л',
  m: 'м',
  n: 'н',
  o: 'о',
  p: 'п',
  q: 'к',
  r: 'р',
  s: 'с',
  t: 'т',
  u: 'у',
  v: 'в',
  w: 'в',
  x: 'кс',
  y: 'и',
  z: 'з',
}

function transliterateLatinNameToCyrillic(value: string): string {
  const normalized = value.toLowerCase().replace(/[^a-z\s-]/g, ' ').trim()
  if (!normalized) {
    return ''
  }

  let converted = normalized
  LATIN_TO_CYRILLIC_NAME_DIGRAPHS.forEach(([latin, cyrillic]) => {
    converted = converted.split(latin).join(cyrillic)
  })

  const transliterated = converted
    .split('')
    .map((char) => (/[a-z]/.test(char) ? (LATIN_TO_CYRILLIC_NAME_MAP[char] ?? char) : char))
    .join('')

  return transliterated.replace(/\s+/g, ' ').trim()
}

function normalizeCharacterIdentity(value: string): string {
  return value
    .toLowerCase()
    .replace(/[^0-9a-zа-яё\s-]/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim()
}

function normalizeCharacterNoteValue(value: string | null | undefined): string {
  return (value ?? '')
    .replace(/\r\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, STORY_CHARACTER_NOTE_MAX_LENGTH)
}

function normalizeCharacterRaceValue(value: string | null | undefined): string {
  return (value ?? '')
    .replace(/\r\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, STORY_CHARACTER_RACE_MAX_LENGTH)
}

function normalizeCharacterAdditionalValue(value: string | null | undefined): string {
  return (value ?? '')
    .replace(/\r\n/g, '\n')
    .trim()
    .slice(0, STORY_CHARACTER_ADDITIONAL_FIELD_MAX_LENGTH)
}

function buildCharacterAliases(value: string): string[] {
  const normalized = normalizeCharacterIdentity(value)
  if (!normalized) {
    return []
  }

  const aliases = new Set<string>([normalized])
  normalized.split(' ').forEach((token) => {
    if (token.length >= 2) {
      aliases.add(token)
    }
  })
  return [...aliases]
}

function buildIdentityTriggerAliases(title: string, triggers: string[]): string[] {
  const titleTokens = normalizeStoryMatchTokens(title)
  const primaryTitleToken = titleTokens[0] ?? ''
  if (!primaryTitleToken) {
    return []
  }

  const aliases = new Set<string>()
  triggers
    .flatMap((trigger) => splitStoryTriggerCandidates(trigger))
    .forEach((trigger) => {
      const normalizedTrigger = normalizeCharacterIdentity(trigger)
      if (!normalizedTrigger) {
        return
      }

      const triggerTokens = normalizeStoryMatchTokens(normalizedTrigger)
      const primaryTriggerToken = triggerTokens[0] ?? ''
      if (!primaryTriggerToken) {
        return
      }

      const isRelatedIdentity =
        primaryTriggerToken === primaryTitleToken ||
        (primaryTriggerToken.length >= 4 && primaryTitleToken.startsWith(primaryTriggerToken)) ||
        (primaryTitleToken.length >= 4 && primaryTriggerToken.startsWith(primaryTitleToken))
      if (!isRelatedIdentity) {
        return
      }

      aliases.add(normalizedTrigger)
      if (triggerTokens.length <= 2) {
        aliases.add(primaryTriggerToken)
      }
    })

  return [...aliases]
}

function extractSpeakerLookupValues(rawSpeakerName: string): string[] {
  const normalizedSpeakerName = rawSpeakerName.replace(/\r\n/g, ' ').trim()
  if (!normalizedSpeakerName) {
    return []
  }

  const values = new Set<string>([normalizedSpeakerName])
  const addTransliterated = (value: string) => {
    const hasLatin = /[a-z]/i.test(value)
    const hasCyrillic = /[а-яё]/i.test(value)
    if (!hasLatin || hasCyrillic) {
      return
    }
    const transliterated = transliterateLatinNameToCyrillic(value)
    if (transliterated) {
      values.add(transliterated)
    }
  }
  addTransliterated(normalizedSpeakerName)

  if (normalizedSpeakerName.startsWith('@')) {
    const withoutAt = normalizedSpeakerName.slice(1).trim()
    if (withoutAt) {
      values.add(withoutAt)
      addTransliterated(withoutAt)
      const withoutAtAndPrefix = withoutAt.replace(SPEAKER_REFERENCE_PREFIX_PATTERN, '').trim()
      if (withoutAtAndPrefix) {
        values.add(withoutAtAndPrefix)
        addTransliterated(withoutAtAndPrefix)
      }
    }
  }

  const withoutPrefix = normalizedSpeakerName.replace(SPEAKER_REFERENCE_PREFIX_PATTERN, '').trim()
  if (withoutPrefix && withoutPrefix !== normalizedSpeakerName) {
    values.add(withoutPrefix)
    addTransliterated(withoutPrefix)
  }

  return [...values]
}

function sortGamesByActivity(games: StoryGameSummary[]): StoryGameSummary[] {
  return [...games].sort(
    (left, right) =>
      new Date(right.last_activity_at).getTime() - new Date(left.last_activity_at).getTime() || right.id - left.id,
  )
}

function readFileAsDataUrl(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onerror = () => reject(new Error('Не удалось прочитать файл'))
    reader.onload = () => {
      if (typeof reader.result !== 'string') {
        reject(new Error('Некорректный формат файла'))
        return
      }
      resolve(reader.result)
    }
    reader.readAsDataURL(file)
  })
}

function normalizeWorldCardTriggersDraft(draft: string, fallbackTitle?: string): string[] {
  const seen = new Set<string>()
  const normalized: string[] = []

  const pushTrigger = (value: string) => {
    const trimmed = value.replace(/\s+/g, ' ').trim()
    if (!trimmed) {
      return
    }
    const key = trimmed.toLowerCase()
    if (seen.has(key)) {
      return
    }
    seen.add(key)
    normalized.push(trimmed)
  }

  splitStoryTriggerCandidates(draft).forEach((part) => pushTrigger(part))
  if (fallbackTitle) {
    pushTrigger(fallbackTitle)
  }

  return normalized.slice(0, 40)
}

function normalizePlotCardTriggersDraft(draft: string): string[] {
  return normalizeWorldCardTriggersDraft(draft).slice(0, 40)
}

function normalizeCharacterTriggersDraft(draft: string, fallbackName: string): string[] {
  return normalizeWorldCardTriggersDraft(draft, fallbackName).slice(0, 40)
}

function createInstructionTemplateSignature(title: string, content: string): string {
  const normalizedTitle = title.replace(/\s+/g, ' ').trim().toLowerCase()
  const normalizedContent = content.replace(/\s+/g, ' ').trim().toLowerCase()
  return `${normalizedTitle}::${normalizedContent}`
}

function normalizeStoryMemoryOptimizationMode(value: string | null | undefined): StoryMemoryOptimizationMode {
  if (value === 'enhanced' || value === 'maximum' || value === 'standard') {
    return value
  }
  return 'standard'
}

function normalizeStoryAppearanceBackgroundMode(value: string | null | undefined): StoryAppearanceBackgroundMode {
  return value === 'custom' ? 'custom' : STORY_APPEARANCE_DEFAULT_BACKGROUND_MODE
}

function normalizeStoryAppearanceUiStyle(value: string | null | undefined): StoryAppearanceUiStyle {
  if (value === 'cyberpunk' || value === 'fantasy' || value === 'modern') {
    return value
  }
  return STORY_APPEARANCE_DEFAULT_UI_STYLE
}

function normalizeStoryAppearanceTextStyle(value: string | null | undefined): StoryAppearanceTextStyle {
  if (value === 'serif' || value === 'terminal') {
    return value
  }
  return STORY_APPEARANCE_DEFAULT_TEXT_STYLE
}

function normalizeStoryAppearanceColor(value: string | null | undefined, fallback: string): string {
  const normalized = (value ?? '').trim()
  if (!STORY_APPEARANCE_HEX_COLOR_PATTERN.test(normalized)) {
    return fallback
  }
  return normalized.toUpperCase()
}

function getStoryMemoryLayerLabel(
  layer: StoryMemoryDevLayer,
  mode: StoryMemoryOptimizationMode,
): string {
  if (layer === 'archive') {
    return 'Архив полных ходов · резервная копия'
  }
  const share = STORY_MEMORY_LAYER_SHARE_BY_MODE[mode]?.[layer] ?? STORY_MEMORY_LAYER_SHARE_BY_MODE.standard[layer]
  const title = STORY_MEMORY_LAYER_TITLE[layer]
  const legacyLabelExists = Boolean(AI_MEMORY_LAYER_LABEL[layer])
  return `${title} · ${legacyLabelExists ? share : share}%`
}

function getStoryContextLimitMax(
  modelId: StoryNarratorModelId | string | null | undefined,
  subscriptionMemoryCap?: number | null,
): number {
  if (isStorySubscriptionNarratorModelId(modelId)) {
    const fallbackCap = STORY_SUBSCRIPTION_MODEL_DEFAULT_CAP.get(modelId as StoryNarratorModelId) ?? 8000
    const rawCap =
      typeof subscriptionMemoryCap === 'number' && subscriptionMemoryCap > 0 ? subscriptionMemoryCap : fallbackCap
    return Math.min(STORY_CONTEXT_LIMIT_STANDARD_MAX, Math.max(STORY_CONTEXT_LIMIT_MIN, rawCap))
  }
  if (modelId === 'aion-labs/aion-2.0') {
    return STORY_CONTEXT_LIMIT_AION_MAX
  }
  return STORY_EXTENDED_CONTEXT_NARRATOR_MODELS.has(modelId as StoryNarratorModelId)
    ? STORY_CONTEXT_LIMIT_GLM51_MAX
    : STORY_CONTEXT_LIMIT_STANDARD_MAX
}

function clampStoryContextLimit(
  value: number,
  modelId?: StoryNarratorModelId | string | null,
  subscriptionMemoryCap?: number | null,
): number {
  if (!Number.isFinite(value)) {
    return STORY_DEFAULT_CONTEXT_LIMIT
  }
  const roundedValue = Math.round(value / STORY_CONTEXT_LIMIT_STEP) * STORY_CONTEXT_LIMIT_STEP
  return Math.min(
    getStoryContextLimitMax(modelId, subscriptionMemoryCap),
    Math.max(STORY_CONTEXT_LIMIT_MIN, roundedValue),
  )
}

// Fixed breakpoints for the context-limit slider. Costs are tiered exactly at these
// thresholds, so free-sliding between them adds no value — snapping to the breakpoints
// (6000, 16000, 32000, 64000 and, where the model allows, its extended max) is clearer.
function getStoryContextLimitMarks(maxValue: number): { value: number }[] {
  const breakpoints = [
    STORY_TURN_COST_TIER_1_CONTEXT_LIMIT_MAX,
    STORY_TURN_COST_TIER_2_CONTEXT_LIMIT_MAX,
    STORY_TURN_COST_TIER_3_CONTEXT_LIMIT_MAX,
    STORY_TURN_COST_TIER_4_CONTEXT_LIMIT_MAX,
    STORY_CONTEXT_LIMIT_GLM51_MAX,
  ]
  const values = new Set<number>([STORY_CONTEXT_LIMIT_MIN])
  for (const breakpoint of breakpoints) {
    if (breakpoint >= STORY_CONTEXT_LIMIT_MIN && breakpoint <= maxValue) {
      values.add(breakpoint)
    }
  }
  values.add(maxValue)
  return Array.from(values)
    .sort((a, b) => a - b)
    .map((value) => ({ value }))
}

// Snap an arbitrary context-limit value to the nearest allowed breakpoint mark.
function snapStoryContextLimitToMark(value: number, maxValue: number): number {
  const marks = getStoryContextLimitMarks(maxValue)
  let closest = marks[0]?.value ?? STORY_CONTEXT_LIMIT_MIN
  for (const mark of marks) {
    if (Math.abs(mark.value - value) < Math.abs(closest - value)) {
      closest = mark.value
    }
  }
  return closest
}

function clampStoryResponseMaxTokens(value: number): number {
  if (!Number.isFinite(value)) {
    return STORY_DEFAULT_RESPONSE_MAX_TOKENS
  }
  return Math.min(STORY_RESPONSE_MAX_TOKENS_MAX, Math.max(STORY_RESPONSE_MAX_TOKENS_MIN, Math.round(value)))
}

function sanitizeStoryImageStylePromptDraft(value: string): string {
  return value.replace(/\r\n/g, '\n').replace(/\s+/g, ' ').trimStart().slice(0, STORY_IMAGE_STYLE_PROMPT_MAX_LENGTH)
}

function normalizeStoryImageStylePrompt(value: string | null | undefined): string {
  return sanitizeStoryImageStylePromptDraft(value ?? '').trim()
}


function getStoryNarratorTurnCostTiers(modelId: StoryNarratorModelId): readonly [number, number, number, number, number] {
  if (modelId === 'z-ai/glm-4.7') {
    return STORY_TURN_COST_GLM47_TIERS
  }
  if (modelId === 'z-ai/glm-5.1') {
    return STORY_TURN_COST_GLM51_TIERS
  }
  if (modelId === 'z-ai/glm-5.2') {
    return STORY_TURN_COST_GLM52_TIERS
  }
  if (modelId === 'aion-labs/aion-2.0') {
    return STORY_TURN_COST_AION_TIERS
  }
  if (modelId === 'aion-labs/aion-3.0') {
    return STORY_TURN_COST_AION3_TIERS
  }
  if (modelId === 'deepcogito/cogito-v2.1-671b') {
    return STORY_TURN_COST_COGITO_TIERS
  }
  if (modelId === 'minimax/minimax-m2-her') {
    return STORY_TURN_COST_MINIMAX_M2_HER_TIERS
  }
  if (modelId === 'z-ai/glm-5') {
    return STORY_TURN_COST_GLM5_TIERS
  }
  if (modelId === 'google/gemini-3.1-flash-lite') {
    return STORY_TURN_COST_GEMINI_31_FLASH_LITE_TIERS
  }
  if (modelId === 'google/gemini-2.5-pro') {
    return STORY_TURN_COST_GEMINI_25_PRO_TIERS
  }
  if (modelId === 'anthropic/claude-sonnet-4.6') {
    return STORY_TURN_COST_CLAUDE_SONNET_TIERS
  }
  if (modelId === 'google/gemini-3.1-pro-preview') {
    return STORY_TURN_COST_GEMINI_31_PRO_TIERS
  }
  if (modelId === 'deepseek/deepseek-v4-pro' || modelId === 'deepseek/deepseek-r1-0528') {
    return STORY_TURN_COST_DEEPSEEK_V4_PRO_TIERS
  }
  if (modelId === 'deepseek/deepseek-v3.2' || modelId === 'deepseek/deepseek-chat-v3-0324') {
    return STORY_TURN_COST_DEEPSEEK_TIERS
  }
  if (modelId === 'z-ai/glm-4.7-flash') {
    return STORY_TURN_COST_GLM47_FLASH_TIERS
  }
  if (STORY_TURN_COST_STANDARD_NARRATOR_MODELS.has(modelId)) {
    return STORY_TURN_COST_DEEPSEEK_TIERS
  }
  return STORY_TURN_COST_DEEPSEEK_TIERS
}

