  const isSelectedMenuPlotCardTriggerDriven = Boolean(
    selectedMenuPlotCard && plotCardUsesTriggerMode(selectedMenuPlotCard),
  )
  const openedAiMemoryBlock = useMemo(
    () => (openedAiMemoryBlockId !== null ? aiMemoryBlocks.find((block) => block.id === openedAiMemoryBlockId) ?? null : null),
    [aiMemoryBlocks, openedAiMemoryBlockId],
  )
  const isSelectedMenuWorldCardLocked = Boolean(
    selectedMenuWorldCard && selectedMenuWorldCard.is_locked,
  )
  const isSelectedMenuInstructionActiveUpdating = Boolean(
    selectedMenuInstructionCard && updatingInstructionActiveId === selectedMenuInstructionCard.id,
  )
  const isPlotCardActionLocked = isStoryTurnBusy || isSavingPlotCard || isCreatingGame || deletingPlotCardId !== null
  const isSelectedMenuWorldCardAiEditUpdating = Boolean(
    selectedMenuWorldCard && updatingWorldCardAiEditId === selectedMenuWorldCard.id,
  )
  const canDeleteSelectedMenuWorldCard = Boolean(
    selectedMenuWorldCard && !selectedMenuWorldCard.is_locked,
  )
  const getWorldCardAiEditStatusLabel = useCallback(
    (card: StoryWorldCard): string =>
      card.ai_edit_enabled ? 'Авто состояние: доступно' : 'Авто состояние: запрещено',
    [],
  )
  const getWorldCardAiEditActionLabel = useCallback(
    (card: StoryWorldCard): string =>
      card.ai_edit_enabled ? 'Авто состояние: запрещено' : 'Авто состояние: доступно',
    [],
  )

  const adjustInputHeight = useCallback(() => {
    const node = textAreaRef.current
    if (!node) {
      return
    }

    node.style.height = 'auto'
    const contentHeight = node.scrollHeight
    const nextHeight = Math.min(Math.max(contentHeight, COMPOSER_INPUT_MIN_HEIGHT), COMPOSER_INPUT_MAX_HEIGHT)
    node.style.height = `${nextHeight}px`
    node.style.overflowY = contentHeight > COMPOSER_INPUT_MAX_HEIGHT ? 'auto' : 'hidden'
  }, [])

  const scheduleAdjustInputHeight = useCallback(() => {
    if (inputHeightFrameRef.current !== null) {
      return
    }
    inputHeightFrameRef.current = window.requestAnimationFrame(() => {
      inputHeightFrameRef.current = null
      adjustInputHeight()
    })
  }, [adjustInputHeight])

  const syncComposerDraft = useCallback(
    (
      rawValue: string,
      options?: { updateDom?: boolean; gameId?: number | null; preservePending?: boolean },
    ) => {
      const nextValue = rawValue.slice(0, STORY_PROMPT_MAX_LENGTH)
      const targetGameId = options && 'gameId' in options ? options.gameId ?? null : activeGameIdRef.current
      composerDraftRef.current = nextValue
      persistStoryComposerDraft(user.id, targetGameId, nextValue)
      if (!options?.preservePending) {
        clearStoryComposerPendingDraft(user.id, targetGameId)
      }
      if (options?.updateDom !== false && textAreaRef.current && textAreaRef.current.value !== nextValue) {
        textAreaRef.current.value = nextValue
      }
      if (inputLengthIndicatorRef.current) {
        inputLengthIndicatorRef.current.textContent = `${nextValue.length}/${STORY_PROMPT_MAX_LENGTH}`
      }
      const nextHasPromptText = nextValue.trim().length > 0
      if (hasPromptTextRef.current !== nextHasPromptText) {
        hasPromptTextRef.current = nextHasPromptText
        startTransition(() => setHasPromptText(nextHasPromptText))
      }
      scheduleAdjustInputHeight()
      return nextValue
    },
    [scheduleAdjustInputHeight, user.id],
  )

  const handleComposerInputChange = useCallback(
    (event: ChangeEvent<HTMLTextAreaElement>) => {
      const nextValue = event.currentTarget.value.slice(0, STORY_PROMPT_MAX_LENGTH)
      if (event.currentTarget.value !== nextValue) {
        event.currentTarget.value = nextValue
      }
      syncComposerDraft(nextValue, { updateDom: false })
    },
    [syncComposerDraft],
  )

  useEffect(() => {
    const targetGameId = activeGameId ?? null
    const pendingDraft = readStoryComposerPendingDraft(user.id, targetGameId)
    const pendingMessageWasPersisted = Boolean(
      pendingDraft &&
      targetGameId !== null &&
      messages.some(
        (message) =>
          message.id > pendingDraft.afterMessageId &&
          message.game_id === targetGameId &&
          message.role === 'user' &&
          message.content.replace(/\r\n/g, '\n').trim() === pendingDraft.text.replace(/\r\n/g, '\n').trim(),
      ),
    )

    if (pendingMessageWasPersisted) {
      clearStoryComposerPendingDraft(user.id, targetGameId)
      composerDraftGameIdRef.current = targetGameId
      syncComposerDraft('', { gameId: targetGameId, preservePending: true })
      return
    }

    if (composerDraftGameIdRef.current === targetGameId) {
      return
    }
    composerDraftGameIdRef.current = targetGameId
    syncComposerDraft(readStoryComposerDraft(user.id, targetGameId), {
      gameId: targetGameId,
      preservePending: true,
    })
  }, [activeGameId, messages, syncComposerDraft, user.id])

  const applyUpdatedGameSummary = useCallback((updatedGame: StoryGameSummary) => {
    setActiveGameSummary(updatedGame)
    setGames((previousGames) =>
      sortGamesByActivity(previousGames.map((game) => (game.id === updatedGame.id ? updatedGame : game))),
    )
    setCustomTitleMap((previousMap) => {
      const nextMap = setStoryTitle(previousMap, updatedGame.id, updatedGame.title)
      persistStoryTitleMap(nextMap)
      return nextMap
    })
  }, [])

  const refreshStoryEnvironmentMemorySnapshot = useCallback(
    async (gameId: number) => {
      const payload = await getStoryGame({
        token: authToken,
        gameId,
        assistantTurnsLimit: 1,
        beforeMessageId: null,
      })
      applyUpdatedGameSummary(payload.game)
      setAiMemoryBlocks(normalizeStoryMemoryBlocks(payload.memory_blocks))
    },
    [applyUpdatedGameSummary, authToken],
  )

  const applyActiveMainHeroCardId = useCallback((gameId: number, cardId: number | null) => {
    const updateGame = (game: StoryGameSummary): StoryGameSummary => ({
      ...game,
      active_main_hero_card_id: cardId,
    })
    setActiveGameSummary((previousGame) =>
      previousGame && previousGame.id === gameId ? updateGame(previousGame) : previousGame,
    )
    setGames((previousGames) =>
      sortGamesByActivity(previousGames.map((game) => (game.id === gameId ? updateGame(game) : game))),
    )
  }, [])

  const persistActiveMainHeroCard = useCallback(
    async (cardId: number | null) => {
      if (!activeGameId) {
        return
      }
      const previousCardId = activeGameSummary?.active_main_hero_card_id ?? null
      if (previousCardId === cardId) {
        return
      }
      applyActiveMainHeroCardId(activeGameId, cardId)
      setErrorMessage('')
      try {
        const updatedGame = await updateStoryGameSettings({
          token: authToken,
          gameId: activeGameId,
          activeMainHeroCardId: cardId,
        })
        applyUpdatedGameSummary(updatedGame)
      } catch (error) {
        applyActiveMainHeroCardId(activeGameId, previousCardId)
        const detail = error instanceof Error ? error.message : 'Не удалось переключить главного героя'
        setErrorMessage(detail)
      }
    },
    [activeGameId, activeGameSummary?.active_main_hero_card_id, applyActiveMainHeroCardId, applyUpdatedGameSummary, authToken],
  )

  const handleOpenMainHeroSelectorMenu = useCallback((event: ReactMouseEvent<HTMLElement>) => {
    event.preventDefault()
    event.stopPropagation()
    setMainHeroSelectorAnchorEl(event.currentTarget)
  }, [])

  const handleCloseMainHeroSelectorMenu = useCallback(() => {
    setMainHeroSelectorAnchorEl(null)
  }, [])

