    activeGameId,
    ambientEnabled,
    applyUpdatedGameSummary,
    authToken,
    autoNpcCardsEnabled,
    characterStateEnabled,
    isAdministrator,
    isGenerating,
    isSavingResponseMaxTokens,
    isSavingResponseMaxTokensEnabled,
    isSavingResponseTokenLimit,
    memoryOptimizationEnabled,
    memoryOptimizationMode,
    responseMaxTokens,
    responseMaxTokensEnabled,
