                                          border: 'none',
                                          backgroundColor: 'transparent',
                                          color: 'rgba(198, 210, 228, 0.86)',
                                          fontSize: '0.98rem',
                                          lineHeight: 1,
                                          '&:hover': { backgroundColor: 'transparent' },
                                          '&:active': { backgroundColor: 'transparent' },
