      <input
        ref={worldCardAvatarInputRef}
        type="file"
        accept="image/png,image/jpeg,image/webp,image/gif"
        onChange={handleWorldCardAvatarChange}
        style={{ display: 'none' }}
      />

      <Menu
        anchorEl={cardMenuAnchorEl}
