                      width: '100%',
                      minHeight: 38,
                      borderRadius: 'var(--morius-radius)',
                      border: 'var(--morius-border-width) solid color-mix(in srgb, var(--morius-card-border) 72%, transparent)',
                      backgroundColor: 'var(--morius-card-bg)',
                      color: 'var(--morius-text-primary)',
